            background: transparent;
            border: none;
            color: var(--text-secondary);
            font-family: var(--font-mono);
            font-size: 13px;
            cursor: pointer;
            border-radius: 4px 4px 0 0;
            transition: color 0.25s, background 0.25s;
            white-space: nowrap;
