        .stat-card.red .stat-number { color: var(--accent-red); }
        .stat-card.orange .stat-number { color: var(--accent-orange); }
        .stat-card.blue .stat-number { color: var(--accent-blue); }
        .stat-card.green .stat-number { color: var(--accent-green); }
        .stat-card.pink .stat-number { color: #ec4899; }
        .stat-card.purple .stat-number { color: var(--accent-purple); }

        /* ===== 进度条 ===== */
        .progress-track {
            width: 100%;
            height: 4px;
            background: rgba(255,255,255,0.06);
            border-radius: 2px;
            margin-top: 10px;
            overflow: hidden;
        }

        .progress-bar {
            height: 100%;
            border-radius: 2px;
            max-width: 100%;
            min-width: 0;
            transition: width 1.2s cubic-bezier(0.22, 1, 0.36, 1);
            position: relative;
        }

        .progress-bar.red { background: linear-gradient(90deg, #991b1b, #ef4444); }
        .progress-bar.orange { background: linear-gradient(90deg, #9a3412, #f97316); }
        .progress-bar.blue { background: linear-gradient(90deg, #1e40af, #3b82f6); }
        .progress-bar.green { background: linear-gradient(90deg, #166534, #22c55e); }
        .progress-bar.pink { background: linear-gradient(90deg, #9d174d, #ec4899); }
        .progress-bar.purple { background: linear-gradient(90deg, #6b21a8, #a855f7); }

        .progress-bar::after {
            content: '';
