            box-shadow: 0 0 4px rgba(255,255,255,0.5);
        }

        /* ===== 低值警告闪烁 ===== */
        .stat-number.critical {
            animation: pulse-warn 0.8s ease-in-out infinite alternate;
        }

        @keyframes pulse-warn {
            from { opacity: 1; }
