            display: flex;
            align-items: center;
            gap: 8px;
            letter-spacing: 1px;
        }

        .info-card-title::after {
            content: '';
            flex: 1;
            height: 1px;
            background: var(--border-dim);
        }

        .info-row {
            display: flex;
            justify-content: space-between;
            align-items: center;
            padding: 6px 0;
            border-bottom: 1px solid rgba(255,255,255,0.03);
        }

        .info-row:last-child { border-bottom: none; }

        .info-key {
            font-size: 14px;
            color: var(--text-secondary);
        }

        .info-val {
            font-family: var(--font-mono);
            font-size: 14px;
            color: var(--text-bright);
        }

        .info-val.warning {
            color: var(--accent-yellow);
            text-shadow: 0 0 6px rgba(234,179,8,0.4);
            animation: pulse-warn 1.2s ease-in-out infinite alternate;
        }

        .info-val.danger {
            color: var(--accent-red);
            text-shadow: 0 0 6px rgba(239,68,68,0.4);
            animation: pulse-danger 0.8s ease-in-out infinite alternate;
        }

        /* ===== 营地信息 ===== */
        .camp-row {
            display: flex;
            align-items: center;
            gap: 12px;
            padding: 12px 16px;
            background: var(--bg-panel);
            border: 1px solid var(--border-dim);
            border-radius: 6px;
        }

        .camp-icon { font-size: 20px; }
        .camp-label { font-size: 13px; color: var(--text-secondary); }
        .camp-value { font-family: var(--font-mono); font-size: 15px; color: var(--accent-cyan); }

        /* ===== BMI + 名声 行 ===== */
        .info-duo-row {
            display: flex;
            gap: 12px;
            margin-bottom: 12px;
