            .info-duo-row { flex-direction: column; }
        }

        .info-pill {
            flex: 1;
            display: flex;
            align-items: center;
            gap: 10px;
            padding: 10px 14px;
            background: var(--bg-panel);
            border: 1px solid var(--border-dim);
            border-radius: 6px;
            position: relative;
            overflow: hidden;
        }

        .info-pill::before {
            content: '';
