        .info-pill-value { font-family: var(--font-mono); font-size: 15px; font-weight: 700; }

        .info-pill.bmi .info-pill-value { color: var(--accent-orange); }
        .info-pill.rep .info-pill-value { color: var(--accent-yellow); }

        .info-pill.rep .info-pill-value.rep-bad { color: var(--accent-red); }
        .info-pill.rep .info-pill-value.rep-neutral { color: var(--text-secondary); }
        .info-pill.rep .info-pill-value.rep-good { color: var(--accent-yellow); }

        /* ===== 技能栏 ===== */
        .skills-section {
            margin-top: 12px;
            background: var(--bg-panel);
            border: 1px solid var(--border-dim);
            border-radius: 6px;
            padding: 14px 16px;
        }

        .skills-title {
            font-family: var(--font-mono);
            font-size: 12px;
            color: var(--text-secondary);
            letter-spacing: 1px;
            margin-bottom: 10px;
            display: flex;
            align-items: center;
            gap: 6px;
        }

        .skill-list {
            display: flex;
            flex-direction: column;
            gap: 8px;
        }

        .skill-item {
            display: grid;
            grid-template-columns: auto 1fr auto;
            gap: 0 12px;
            align-items: center;
        }

        .skill-name {
            font-family: var(--font-mono);
            font-size: 13px;
            color: var(--text-bright);
            white-space: nowrap;
        }

        .skill-bar-track {
            height: 4px;
            background: rgba(255,255,255,0.06);
            border-radius: 2px;
            overflow: hidden;
        }

        .skill-bar-fill {
            height: 100%;
            border-radius: 2px;
            background: linear-gradient(90deg, #166534, #22c55e);
            transition: width 0.8s ease;
        }

        .skill-level {
            font-family: var(--font-mono);
            font-size: 12px;
            color: var(--text-secondary);
            min-width: 24px;
            text-align: right;
        }

        .skill-desc {
            grid-column: 1 / -1;
            font-size: 12px;
            color: var(--text-secondary);
            line-height: 1.4;
            padding-left: 0;
            margin-top: -4px;
        }

        /* ===== 物品重量 ===== */
        .item-weight {
            font-family: var(--font-mono);
            font-size: 12px;
            color: var(--accent-orange);
            margin-left: 6px;
        }

        .bag-total {
            display: flex;
            justify-content: flex-end;
            align-items: center;
            gap: 6px;
            margin-top: 8px;
            font-family: var(--font-mono);
            font-size: 12px;
            color: var(--text-secondary);
        }

        .bag-total .total-val {
            color: var(--accent-orange);
            font-weight: 700;
        }

        /* ===== 列表样式 ===== */
        .item-list {
            list-style: none;
