        }

        .event-location {
            font-size: 12px;
            color: var(--accent-cyan);
            font-family: var(--font-mono);
            margin-bottom: 6px;
        }

        .event-desc {
            font-size: 13px;
            color: var(--text-secondary);
            line-height: 1.6;
        }

