            margin-bottom: 8px;
            transition: border-color 0.2s;
        }

        .msg-card:hover { border-color: rgba(255,255,255,0.1); }

        .msg-header {
            display: flex;
            justify-content: space-between;
            margin-bottom: 6px;
        }

        .msg-sender {
            font-family: var(--font-mono);
            font-size: 13px;
            color: var(--accent-cyan);
        }

        .msg-time {
            font-family: var(--font-mono);
            font-size: 12px;
            color: var(--text-secondary);
        }

        .msg-body {
            font-size: 14px;
            color: var(--text-primary);
            line-height: 1.5;
            padding-left: 10px;
            border-left: 2px solid var(--border-dim);
        }

        /* ===== 双栏布局（通讯） ===== */
        .dual-grid {
            display: grid;
            grid-template-columns: 1fr 1fr;
            gap: 16px;
        }

        @media (max-width: 640px) {
            .dual-grid { grid-template-columns: 1fr; }
        }

        /* ===== 底部状态栏 ===== */
        .footer-bar {
            margin-top: 16px;
            padding: 8px 16px;
            background: var(--bg-panel);
            border: 1px solid var(--border-dim);
            border-radius: 4px;
            display: flex;
            justify-content: space-between;
            align-items: center;
            font-family: var(--font-mono);
            font-size: 11px;
            color: var(--text-secondary);
        }

        .footer-dot {
            display: inline-block;
            width: 6px;
            height: 6px;
            border-radius: 50%;
            background: var(--accent-green);
            box-shadow: 0 0 6px var(--accent-green);
            margin-right: 6px;
            animation: blink-dot 2s ease-in-out infinite;
        }

        @keyframes blink-dot {
            0%, 100% { opacity: 1; }
            50% { opacity: 0.3; }
        }

        /* ===== 生理状态栏 ===== */
        .status-effects {
            display: grid;
            grid-template-columns: 1fr 1fr;
            gap: 12px;
            margin-bottom: 16px;
        }

        @media (max-width: 640px) {
            .status-effects { grid-template-columns: 1fr; }
        }

        .effect-card {
            background: var(--bg-panel);
            border: 1px solid var(--border-dim);
            border-radius: 6px;
            padding: 14px 16px;
            position: relative;
            overflow: hidden;
        }

        .effect-card::before {
            content: '';
            position: absolute;
            top: 0;
            left: 0;
            right: 0;
            height: 2px;
        }

        .effect-card.physical::before {
            background: linear-gradient(90deg, var(--accent-red), var(--accent-orange));
        }

        .effect-card.mental::before {
            background: linear-gradient(90deg, #ec4899, var(--accent-purple));
        }

        .effect-title {
            font-family: var(--font-mono);
            font-size: 12px;
            color: var(--text-secondary);
            letter-spacing: 1px;
            margin-bottom: 8px;
            display: flex;
            align-items: center;
            gap: 6px;
        }

        .effect-title .emoji { font-size: 14px; }

        .effect-body {
            font-size: 14px;
            color: var(--text-primary);
            line-height: 1.7;
            min-height: 20px;
        }

        .effect-body .tag {
            display: inline-block;
            padding: 2px 8px;
            border-radius: 3px;
            font-size: 12px;
            font-family: var(--font-mono);
            margin: 2px 4px 2px 0;
        }

        .effect-body .tag.negative {
            background: rgba(239,68,68,0.12);
            color: var(--accent-red);
            border: 1px solid rgba(239,68,68,0.2);
        }

        .effect-body .tag.positive {
            background: rgba(34,197,94,0.12);
            color: var(--accent-green);
            border: 1px solid rgba(34,197,94,0.2);
        }

        .effect-body .tag.warning {
            background: rgba(234,179,8,0.12);
            color: var(--accent-yellow);
            border: 1px solid rgba(234,179,8,0.2);
            animation: pulse-warn 1.5s ease-in-out infinite alternate;
        }

        /* ===== 世界地图组件 ===== */
        .map-section {
            display: flex;
            flex-direction: column;
            gap: 16px;
            margin-bottom: 16px;
        }

        .map-container {
            width: 100%;
            background: var(--bg-panel);
            border: 1px solid var(--border-dim);
            border-radius: 8px;
            padding: 12px;
            position: relative;
            overflow: hidden;
        }

        .map-container::before {
            content: '';
            position: absolute;
            inset: 0;
            background:
                repeating-linear-gradient(0deg, transparent, transparent 29px, rgba(6,182,212,0.04) 29px, rgba(6,182,212,0.04) 30px),
                repeating-linear-gradient(90deg, transparent, transparent 29px, rgba(6,182,212,0.04) 29px, rgba(6,182,212,0.04) 30px);
            pointer-events: none;
        }

        .world-map {
            width: 100%;
            height: auto;
            display: block;
        }

        .continent-path {
            cursor: pointer;
            stroke: rgba(6,182,212,0.25);
            stroke-width: 0.5;
            transition: fill 0.3s, stroke 0.3s, filter 0.3s;
        }

        .continent-path:hover {
            stroke-width: 1;
            filter: brightness(1.6);
        }

        .continent-path.active {
            stroke-width: 1.2;
            filter: brightness(1.8) drop-shadow(0 0 6px currentColor);
        }

        .continent-path.asia     { fill: rgba(239,68,68,0.18); stroke: rgba(239,68,68,0.35); }
        .continent-path.europe   { fill: rgba(59,130,246,0.18); stroke: rgba(59,130,246,0.35); }
        .continent-path.africa   { fill: rgba(249,115,22,0.18); stroke: rgba(249,115,22,0.35); }
        .continent-path.namerica { fill: rgba(34,197,94,0.18); stroke: rgba(34,197,94,0.35); }
        .continent-path.samerica { fill: rgba(234,179,8,0.18); stroke: rgba(234,179,8,0.35); }
        .continent-path.oceania  { fill: rgba(168,85,247,0.18); stroke: rgba(168,85,247,0.35); }

        .continent-path.asia:hover,     .continent-path.asia.active     { fill: rgba(239,68,68,0.32); stroke: var(--accent-red); }
        .continent-path.europe:hover,   .continent-path.europe.active   { fill: rgba(59,130,246,0.32); stroke: var(--accent-blue); }
        .continent-path.africa:hover,   .continent-path.africa.active   { fill: rgba(249,115,22,0.32); stroke: var(--accent-orange); }
        .continent-path.namerica:hover, .continent-path.namerica.active { fill: rgba(34,197,94,0.32); stroke: var(--accent-green); }
        .continent-path.samerica:hover, .continent-path.samerica.active { fill: rgba(234,179,8,0.32); stroke: var(--accent-yellow); }
        .continent-path.oceania:hover,  .continent-path.oceania.active  { fill: rgba(168,85,247,0.32); stroke: var(--accent-purple); }

        .continent-label {
            font-family: var(--font-mono);
            font-size: 8px;
            fill: var(--text-secondary);
            pointer-events: none;
            letter-spacing: 1px;
            text-anchor: middle;
            dominant-baseline: middle;
        }

        .continent-label.active { fill: var(--text-bright); }

        .map-scanline {
            position: absolute;
            top: 0;
            left: 0;
            width: 2px;
            height: 100%;
            background: linear-gradient(180deg, transparent, rgba(6,182,212,0.15), transparent);
            pointer-events: none;
            animation: map-scan 4s linear infinite;
        }

        @keyframes map-scan {
            0% { left: -2px; }
            100% { left: 100%; }
        }

        .continent-detail {
            width: 100%;
            background: var(--bg-panel);
            border: 1px solid var(--border-dim);
            border-radius: 6px;
            padding: 16px;
            min-height: 80px;
            animation: panel-in 0.3s ease;
        }

        .continent-detail-header {
            display: flex;
            align-items: center;
            gap: 10px;
            margin-bottom: 10px;
        }

        .continent-detail-icon { font-size: 22px; }

        .continent-detail-name {
            font-family: var(--font-mono);
            font-size: 15px;
            font-weight: 700;
            letter-spacing: 1px;
        }

        .continent-detail-name.asia     { color: var(--accent-red); }
        .continent-detail-name.europe   { color: var(--accent-blue); }
        .continent-detail-name.africa   { color: var(--accent-orange); }
        .continent-detail-name.namerica { color: var(--accent-green); }
        .continent-detail-name.samerica { color: var(--accent-yellow); }
        .continent-detail-name.oceania  { color: var(--accent-purple); }

        .continent-detail-body {
            font-size: 14px;
            color: var(--text-primary);
            line-height: 1.7;
        }

        .map-hint {
            font-family: var(--font-mono);
            font-size: 11px;
            color: var(--text-secondary);
            text-align: center;
            letter-spacing: 1px;
            opacity: 0.6;
        }

        /* ===== 响应式 ===== */
        @media (max-width: 700px) {
            .terminal { border-radius: 0; border: none; border-top: 2px solid var(--accent-red); border-bottom: 2px solid var(--accent-red-dim); }
            .tab-content { max-height: 400px; padding: 15px; }
            .stat-number { font-size: 22px; }
        }
    </style>
</head>
<body>
<!-- disable-default-loading -->
<textarea id="data-source" style="display:none;">$1</textarea>
<div class="noise-overlay"></div>

<div class="terminal">
    <!-- 顶部标题 -->
    <header class="header">
        <div class="header-title">☠️ 末世生存终端</div>
        <div class="header-sub">SURVIVAL STATUS TERMINAL v2.7</div>
        <div class="header-line"></div>
    </header>

    <!-- 标签导航 -->
    <div class="tab-nav-wrapper">
    <nav class="tab-nav" id="tabNav">
        <button class="tab-btn active" type="button" data-tab="basic">🩺 个人状态</button>
        <button class="tab-btn" type="button" data-tab="env">🌍 环境信息</button>
        <button class="tab-btn" type="button" data-tab="bag">🎒 背包物品</button>
        <button class="tab-btn" type="button" data-tab="vehicle">🚗 载具栏</button>
        <button class="tab-btn" type="button" data-tab="partner">👥 队友</button>
        <button class="tab-btn" type="button" data-tab="npc">🧟 人物</button>
        <button class="tab-btn" type="button" data-tab="world">☄️ 世界事件</button>
        <button class="tab-btn" type="button" data-tab="msg">📡 通讯系统</button>
    </nav>
    </div>

    <!-- ====== 1. 个人状态 ====== -->
    <section class="tab-content active" id="basic">
        <div class="stat-grid" id="statGrid"></div>
        <div class="info-duo-row" id="bmiRepRow"></div>
        <div class="status-effects" id="statusEffects"></div>
        <div class="camp-row" id="campRow"></div>
        <div class="skills-section" id="skillsSection"></div>
    </section>

    <!-- ====== 2. 环境信息 ====== -->
    <section class="tab-content" id="env">
        <div class="info-card" id="envCard"></div>
    </section>

    <!-- ====== 3. 背包物品 ====== -->
    <section class="tab-content" id="bag">
        <div class="info-card">
            <div class="info-card-title">🎒 物品清单</div>
            <ul class="item-list" id="bagList"></ul>
            <div class="bag-total" id="bagTotal"></div>
        </div>
    </section>

    <!-- ====== 4. 载具栏 ====== -->
    <section class="tab-content" id="vehicle">
        <div class="info-card">
            <div class="info-card-title">🚗 载具状态</div>
            <ul class="item-list" id="vehicleList"></ul>
        </div>
    </section>

    <!-- ====== 5. 队友 ====== -->
    <section class="tab-content" id="partner">
        <div class="info-card">
            <div class="info-card-title">👥 队友列表</div>
            <ul class="item-list" id="partnerList"></ul>
        </div>
    </section>

    <!-- ====== 6. 幸存者NPC ====== -->
    <section class="tab-content" id="npc">
        <div class="info-card">
            <div class="info-card-title">🧟 NPC人物</div>
            <ul class="item-list" id="npcList"></ul>
        </div>
    </section>

    <!-- ====== 7. 世界事件 ====== -->
    <section class="tab-content" id="world">
        <div class="map-section" id="mapSection"></div>
        <div class="info-card">
            <div class="info-card-title">☄️ 世界动向</div>
            <div id="worldEvents"></div>
        </div>
    </section>

    <!-- ====== 8. 通讯系统 ====== -->
    <section class="tab-content" id="msg">
        <div class="dual-grid" id="msgGrid"></div>
    </section>

    <!-- 底部状态栏 -->
    <div class="footer-bar">
        <span><span class="footer-dot"></span>TERMINAL ONLINE</span>
        <span>SIGNAL: NOMINAL</span>
        <span id="clock">--:--:--</span>
    </div>
</div>

<script>
    // ===== 标签页切换 =====
    const tabBtns = document.querySelectorAll('.tab-btn');
    const tabContents = document.querySelectorAll('.tab-content');

    tabBtns.forEach(btn => {
        btn.addEventListener('click', () => {
            tabBtns.forEach(b => b.classList.remove('active'));
            tabContents.forEach(c => c.classList.remove('active'));
            btn.classList.add('active');
            const tabId = btn.getAttribute('data-tab');
            const target = document.getElementById(tabId);
            if (target) {
                target.classList.add('active');
            }
        });
    });

    // ===== 底部实时时钟 =====
    const clockEl = document.getElementById('clock');
    function updateClock() {
        const now = new Date();
        clockEl.textContent = now.toLocaleTimeString('zh-CN', { hour12: false });
    }
    updateClock();
    setInterval(updateClock, 1000);

    // ===== 数据解析与渲染 =====
    function getHtml(node) {
        if (!node) return '';
        if (node.firstChild && node.firstChild.nodeType === Node.CDATA_SECTION_NODE) {
            return node.firstChild.textContent.trim();
        }
        return node.innerHTML ? node.innerHTML.trim() : node.textContent.trim();
    }

    function renderUI(doc, rawText) {
        const dataRoot = doc.querySelector('data_block') || doc;
        const get = (tag) => dataRoot.querySelector(tag)?.textContent.trim() || '';
        const getGHtml = (tag) => getHtml(dataRoot.querySelector(tag));

        // ===== 1. 个人状态 - 属性卡片 =====
        const stats = [
            { label: '❤️ HP / 生命值', key: 'hp', cls: 'red' },
            { label: '🍖 HUNGER / 饱食度', key: 'hunger', cls: 'orange' },
            { label: '💧 THIRST / 饱水度', key: 'thirst', cls: 'blue' },
            { label: '⚡ STAMINA / 体力', key: 'stamina', cls: 'green' },
            { label: '🧠 MORALE / 情绪值', key: 'morale', cls: 'pink' },
            { label: '🦠 INFECTION / 感染值', key: 'infection', cls: 'purple' }
        ];

        const statGrid = document.getElementById('statGrid');
        statGrid.innerHTML = stats.map(s => {
            const current = parseFloat(get(s.key + '_current')) || 0;
            const max = parseFloat(get(s.key + '_max')) || 100;
            const pct = max > 0 ? Math.max(0, Math.min(100, (current / max) * 100)) : 0;
            let warnCls = '';
            if (s.key === 'infection' && current >= 60) warnCls = ' danger-high';
            else if (s.key !== 'infection' && current <= 20) warnCls = ' critical';
            return `
                <div class="stat-card ${s.cls}">
                    <div class="stat-label">${s.label}</div>
                    <div class="stat-value-row">
                        <span class="stat-number${warnCls}">${Math.round(current)}</span>
                        <span class="stat-max">/ ${Math.round(max)}</span>
                    </div>
                    <div class="progress-track">
                        <div class="progress-bar ${s.cls}" style="width: 0%" data-width="${pct}%"></div>
                    </div>
                </div>`;
        }).join('');

        // ===== 1. BMI + 名声 =====
        const bmiVal = get('bmi') || '标准';
        const repVal = get('reputation') || '默默无闻';
        const bmiColors = { '过瘦': '#3b82f6', '较瘦': '#06b6d4', '标准': '#22c55e', '较胖': '#f97316', '过胖': '#ef4444' };
        const bmiIcons = { '过瘦': '🦴', '较瘦': '🧍', '标准': '💪', '较胖': '🏋️', '过胖': '🐘' };
        const repClasses = { '遗臭万年': 'rep-bad', '劣迹斑斑': 'rep-bad', '默默无闻': 'rep-neutral', '声誉鹊起': 'rep-good', '青史留名': 'rep-good' };
        const repIcons = { '遗臭万年': '💀', '劣迹斑斑': '⚠️', '默默无闻': '😐', '声誉鹊起': '🌟', '青史留名': '👑' };

        document.getElementById('bmiRepRow').innerHTML = `
            <div class="info-pill bmi">
                <span class="info-pill-icon">${bmiIcons[bmiVal] || '💪'}</span>
                <div class="info-pill-body">
                    <div class="info-pill-label">BMI / 体型</div>
                    <div class="info-pill-value" style="color:${bmiColors[bmiVal] || 'var(--accent-orange)'}">${bmiVal}</div>
                </div>
            </div>
            <div class="info-pill rep">
                <span class="info-pill-icon">${repIcons[repVal] || '😐'}</span>
                <div class="info-pill-body">
                    <div class="info-pill-label">REPUTATION / 名声</div>
                    <div class="info-pill-value ${repClasses[repVal] || 'rep-neutral'}">${repVal}</div>
                </div>
            </div>`;

        // ===== 1. 生理/心理状态 =====
        const statusEffects = document.getElementById('statusEffects');
        statusEffects.innerHTML = `
            <div class="effect-card physical">
                <div class="effect-title"><span class="emoji">🩸</span> PHYSICAL / 生理状态</div>
                <div class="effect-body">${getGHtml('physical_status') || '无异常'}</div>
            </div>
            <div class="effect-card mental">
                <div class="effect-title"><span class="emoji">💭</span> MENTAL / 心理状态</div>
                <div class="effect-body">${getGHtml('mental_status') || '无异常'}</div>
            </div>`;

        // ===== 1. 营地 =====
        const campRow = document.getElementById('campRow');
        campRow.innerHTML = `
            <span class="camp-icon">🏕️</span>
            <div>
                <div class="camp-label">所属营地</div>
                <div class="camp-value">${get('camp') || '流浪'}</div>
            </div>`;

        // ===== 1. 技能栏 =====
        const skillsSection = document.getElementById('skillsSection');
        const skillItems = Array.from(dataRoot.querySelectorAll('skills > skill'));
        if (skillItems.length > 0) {
            skillsSection.innerHTML = `
                <div class="skills-title">⚔️ SKILLS / 技能栏</div>
                <div class="skill-list">
                    ${skillItems.map(sk => {
                        const skName = sk.querySelector('name')?.textContent.trim() || '';
                        const skLevel = Math.max(1, Math.min(10, parseInt(sk.querySelector('level')?.textContent.trim()) || 1));
                        const skDesc = sk.querySelector('desc')?.textContent.trim() || '';
                        const pct = (skLevel / 10) * 100;
                        return `<div class="skill-item">
                            <span class="skill-name">${skName}</span>
                            <div class="skill-bar-track"><div class="skill-bar-fill" style="width:${pct}%"></div></div>
                            <span class="skill-level">Lv.${skLevel}</span>
                            ${skDesc ? `<div class="skill-desc">${skDesc}</div>` : ''}
                        </div>`;
                    }).join('')}
                </div>`;
        } else {
            skillsSection.innerHTML = `
                <div class="skills-title">⚔️ SKILLS / 技能栏</div>
                <div style="font-size:13px; color:var(--text-secondary); text-align:center; padding:8px 0;">暂无技能</div>`;
        }

        // ===== 2. 环境信息 =====
        const envCard = document.getElementById('envCard');
        const radiationVal = get('radiation');
        const tempVal = get('temperature');
        const noiseVal = getGHtml('noise');
        const comfortVal = parseFloat(get('comfort')) || 0;
        const comfortLabel = comfortVal <= 20 ? '恶劣' : comfortVal <= 40 ? '较差' : comfortVal <= 60 ? '一般' : comfortVal <= 80 ? '较好' : '舒适';
        const comfortColor = comfortVal <= 20 ? 'var(--accent-red)' : comfortVal <= 40 ? 'var(--accent-orange)' : comfortVal <= 60 ? 'var(--accent-yellow)' : comfortVal <= 80 ? 'var(--accent-green)' : '#22d3ee';
        const comfortWarnCls = comfortVal <= 20 ? ' danger' : comfortVal <= 40 ? ' warning' : '';
        const hatredVal = parseFloat(get('hatred')) || 0;
        const hatredLabel = hatredVal <= 30 ? '安全' : hatredVal <= 50 ? '窥伺' : hatredVal <= 70 ? '标记' : hatredVal <= 90 ? '猎杀' : '天罚';
        const hatredColor = hatredVal <= 30 ? 'var(--accent-green)' : hatredVal <= 50 ? 'var(--accent-yellow)' : hatredVal <= 70 ? 'var(--accent-orange)' : hatredVal <= 90 ? 'var(--accent-red)' : '#dc2626';
        const hatredWarnCls = hatredVal >= 71 ? ' danger' : hatredVal >= 51 ? ' warning' : '';
        envCard.innerHTML = `
            <div class="info-card-title">🌍 环境扫描</div>
            <div class="info-row">
                <span class="info-key">📍 当前位置</span>
                <span class="info-val">${getGHtml('location') || '未知'}</span>
            </div>
            <div class="info-row">
                <span class="info-key">🕐 时间 / 天气</span>
                <span class="info-val">${getGHtml('time_weather') || '未知'}</span>
            </div>
            <div class="info-row">
                <span class="info-key">🌡️ 体感温度</span>
                <span class="info-val">${tempVal || '未知'}</span>
            </div>
            <div class="info-row">
                <span class="info-key">☢️ 辐射指数</span>
                <span class="info-val${radiationVal && parseFloat(radiationVal) >= 50 ? ' danger' : radiationVal && parseFloat(radiationVal) >= 20 ? ' warning' : ''}">${radiationVal || '未知'}</span>
            </div>
            <div class="info-row">
                <span class="info-key">🏠 舒适度</span>
                <span class="info-val${comfortWarnCls}" style="color:${comfortColor}">${comfortVal} · ${comfortLabel}</span>
            </div>
            <div style="margin:6px 0 2px;">
                <div class="progress-track" style="height:6px;">
                    <div class="progress-bar" style="width:${comfortVal}%; background:linear-gradient(90deg, ${comfortColor}, ${comfortColor});"></div>
                </div>
            </div>
            <div class="info-row">
                <span class="info-key">⚠️ 威胁等级</span>
                <span class="info-val warning">${getGHtml('threat_level') || '未知'}</span>
            </div>
            <div class="info-row">
                <span class="info-key">🔊 周围动静</span>
                <span class="info-val">${noiseVal || '安静'}</span>
            </div>
            <div class="info-row">
                <span class="info-key">👁️ 仇恨值</span>
                <span class="info-val${hatredWarnCls}" style="color:${hatredColor}">${hatredVal} · ${hatredLabel}</span>
            </div>
            <div style="margin:6px 0 2px;">
                <div class="progress-track" style="height:6px;">
                    <div class="progress-bar" style="width:${hatredVal}%; background:linear-gradient(90deg, ${hatredColor}, ${hatredColor});"></div>
                </div>
            </div>`;

        // ===== 3. 背包物品 =====
        const renderItemList = (selector, containerId, itemFactory) => {
            const items = Array.from(dataRoot.querySelectorAll(selector));
            const container = document.getElementById(containerId);
            container.innerHTML = items.length > 0
                ? items.map(itemFactory).join('')
                : '<li style="color:var(--text-secondary); justify-content:center;">暂无数据</li>';
        };

        renderItemList('inventory > item', 'bagList', item => {
            const g = (tag) => item.querySelector(tag)?.textContent.trim() || '';
            const gH = (tag) => getHtml(item.querySelector(tag));
            const weight = g('weight');
            return `<li><span class="item-name">${g('name')}</span><span class="item-detail">${g('detail') || gH('desc') || ''}${weight ? `<span class="item-weight">${weight}kg</span>` : ''}</span></li>`;
        });

        // 计算背包总重量
        const bagTotalEl = document.getElementById('bagTotal');
        let totalWeight = 0;
        const allItems = Array.from(dataRoot.querySelectorAll('inventory > item'));
        allItems.forEach(item => {
            const w = parseFloat(item.querySelector('weight')?.textContent.trim()) || 0;
            totalWeight += w;
        });
        if (allItems.length > 0) {
