                            contentStr = contentNode.firstChild && contentNode.firstChild.nodeType === Node.CDATA_SECTION_NODE
                                ? contentNode.firstChild.textContent.trim()
                                : contentNode.innerHTML ? contentNode.innerHTML.trim() : contentNode.textContent.trim();
