            min-height: 100vh;
            -webkit-font-smoothing: antialiased;
            overflow-x: hidden;
            overflow-y: auto;
            position: relative;
        }

        /* Toàn màn hình canvas hạt động */
        #particle-canvas {
            position: fixed;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            z-index: 0;
            pointer-events: none;
        }

        /* --------------------------
           Cửa sổ Popup Cảnh báo
        -------------------------- */
        .popup-overlay {
            position: fixed;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            background: rgba(0,0,0,0.85);
            z-index: 999;
            display: flex;
            justify-content: center;
            align-items: center;
            opacity: 1;
            transition: opacity 0.5s ease;
        }
        .popup-window {
            background: #111;
            border: 2px solid #ff0000;
            border-radius: 4px;
            width: 90%;
            max-width: 450px;
            padding: 25px;
            box-shadow: 0 0 30px #ff0000;
            text-align: center;
            animation: popupFade 0.6s ease;
        }
        @keyframes popupFade {
            from { transform: scale(0.8); opacity: 0; }
            to { transform: scale(1); opacity: 1; }
        }
        .popup-title {
            font-size: 1.5em;
            color: #ff0000;
            font-weight: 900;
            margin-bottom: 15px;
            animation: warn 1s infinite alternate;
        }
        .popup-text {
            font-size: 1.1em;
            color: #ccc;
            margin-bottom: 20px;
            line-height: 1.6;
        }
        .popup-btn {
            background: #222;
            border: 1px solid #ff0000;
            color: #ff0000;
            padding: 10px 25px;
            font-size: 1em;
            border-radius: 3px;
            cursor: pointer;
            font-weight: 700;
            transition: 0.3s;
        }
        .popup-btn:hover {
            background: #ff0000;
            color: #000;
        }

        /* --------------------------
           Đếm ngược 24H (Responsive)
        -------------------------- */
        .countdown-box {
            width: 100%;
            max-width: 700px;
            text-align: center;
            margin-bottom: 15px;
            z-index: 2;
            padding: 0 10px;
        }
        .countdown {
            font-size: clamp(1.4em, 7vw, 2.8em);
            font-weight: 900;
            color: #ff0000;
            text-shadow: 0 0 20px #ff0000, 0 0 40px #ff0000;
            letter-spacing: clamp(2px, 0.8vw, 6px);
            animation: warn 0.7s infinite alternate;
            font-family: 'Courier New', monospace;
            background: linear-gradient(90deg, #000, #220000, #000);
            padding: 10px clamp(8px, 3vw, 25px);
            border-radius: 8px;
            border: 1px solid #ff0000;
            display: inline-block;
            position: relative;
            white-space: nowrap;
        }
        /* Trang trí đếm ngược */
        .countdown::before {
            content: "▓▒░";
            color: #00FF00;
            margin-right: 0.4em;
            animation: blink 1s infinite alternate;
        }
        .countdown::after {
            content: "░▒▓";
            color: #00FF00;
            margin-left: 0.4em;
            animation: blink 1s infinite alternate;
        }
        .countdown-label {
            font-size: clamp(0.8em, 2.5vw, 1.1em);
            color: #999;
            margin-top: 8px;
            font-family: monospace;
        }

        .info-card {
            background: var(--card-bg);
            border-radius: 6px;
            padding: 35px;
            max-width: 700px;
            width: 100%;
            position: relative;
            z-index: 1;
            overflow: hidden;
            border: 1px solid #ff0000;
            box-shadow: 0 0 30px rgba(255, 0, 0, 0.6);
            transition: transform 0.2s ease-out;
            animation: fadeIn 0.8s ease-out forwards;
            opacity: 0;
        }

        @keyframes fadeIn {
            to { opacity: 1; }
        }

        .info-card::before {
            content: '';
            position: absolute;
            top: 0;
            left: 0;
            right: 0;
            bottom: 0;
            border-radius: 6px;
            padding: 2px;
            background: conic-gradient(from var(--angle), var(--border-color-1), var(--border-color-2), var(--border-color-1));
            -webkit-mask: linear-gradient(#fff 0 0) content-box, linear-gradient(#fff 0 0);
            -webkit-mask-composite: xor;
            mask-composite: exclude;
            animation: spin 3.5s linear infinite;
            pointer-events: none;
        }

        @property --angle {
          syntax: '<angle>';
          initial-value: 0deg;
          inherits: false;
        }

        @keyframes spin { to { --angle: 360deg; } }

        /* Nhiễu xanh lá */
        .glitch {
            color: #00FF00;
            font-family: monospace;
            animation: blink 1s infinite alternate;
        }
        @keyframes blink {
            0% { opacity: 1; }
            50% { opacity: 0.2; }
            100% { opacity: 1; }
        }

        /* Chớp đỏ tuyệt vọng */
        .warning-blink {
            color: #ff0000;
            font-weight: 700;
            animation: warn 0.7s infinite alternate;
        }
        @keyframes warn {
            0% { text-shadow: 0 0 8px #ff0000; }
            100% { text-shadow: 0 0 20px #ff0000; }
        }

        .doom-greeting {
            text-align: center;
            font-size: 1.4em;
            color: #ff0000;
            margin-bottom: 25px;
            font-weight: 400;
            min-height: 30px;
            transition: opacity 0.4s ease-in-out;
        }

        h1 {
            text-align: center;
            font-size: 2.1em;
            color: #fff;
            margin-top: 0;
            margin-bottom: 30px;
            font-weight: 900;
            letter-spacing: 2px;
        }

        .section {
            margin-bottom: 28px;
            padding-left: 18px;
            border-left: 2px solid #ff0000;
            position: relative;
        }

        .section h3 {
            font-size: 1.3em;
            color: #dddddd;
            margin: 0 0 12px 0;
            font-weight: 700;
            display: flex;
            align-items: center;
        }

        .section p, .section ul {
            margin: 0;
            padding: 0;
            font-size: 1.05em;
