            color: var(--secondary-text);
        }

        .section ul { list-style-type: none; }
        .section strong { color: var(--highlight-color); font-weight: 700; }

        .footer {
            margin-top: 35px;
            text-align: center;
            font-size: 1.15em;
            color: #777777;
        }

        .author {
            margin-top: 25px;
            text-align: right;
            font-size: 1em;
            color: #666666;
        }
        .author strong { color: var(--highlight-color); }

        .icon {
            display: inline-block;
            width: 24px;
            height: 24px;
            margin-right: 10px;
            background-size: contain;
            background-repeat: no-repeat;
            background-position: center;
            opacity: 0.9;
        }

        .icon-warning { background-image: url('data:image/svg+xml;utf8,<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="%23ff0000"><path d="M1 21h22L12 2 1 21zm12-3h-2v-2h2v2zm0-4h-2v-4h2v4z"/></svg>'); }
        .icon-virus { background-image: url('data:image/svg+xml;utf8,<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="%23ff0000"><path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2z"/></svg>'); }
        .icon-time { background-image: url('data:image/svg+xml;utf8,<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="%23ff0000"><path d="M12 2C6.5 2 2 6.5 2 12s4.5 10 10 10 10-4.5 10-10S17.5 2 12 2zm0 18c-4.41 0-8-3.59-8-8s3.59-8 8-8 8 3.59 8 8-3.59 8-8 8zm.5-13h-1v5l4.2 2.5.8-1.2-3.8-2.3V7z"/></svg>'); }
        .icon-monitor { background-image: url('data:image/svg+xml;utf8,<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="%23ff0000"><path d="M20 3H4c-1.1 0-2 .9-2 2v12c0 1.1.9 2 2 2h4v2h8v-2h4c1.1 0 2-.9 2-2V5c0 1.1-.9-2-2-2z"/></svg>'); }

        @media (max-width: 600px) {
            body { padding: 5px; }
            .info-card { padding: 18px; }
            h1 { font-size: 1.7em; }
            .section h3 { font-size: 1.1em; }
            .section p, .section ul { font-size: 0.95em; line-height: 1.7; }
            .doom-greeting { font-size: 1.1em; }
            .popup-window { padding: 18px; }
        }

        @media (max-width: 380px) {
            .countdown::before, .countdown::after { content: none; }
        }

        /* ===== Hiệu ứng nhiễu sóng (Snow canvas) ===== */
        #snow-canvas {
            position: fixed;
            inset: 0;
            z-index: 10001;
            pointer-events: none;
            opacity: 0;
            transition: opacity 0.05s;
            mix-blend-mode: screen;
        }
        #snow-canvas.active {
            opacity: 1;
        }

        /* ===== Trứng phục sinh (Easter Egg) ===== */
        .easter-egg-overlay {
            position: fixed;
            inset: 0;
            z-index: 20000;
            background: #000;
            display: flex;
            flex-direction: column;
            justify-content: center;
            align-items: center;
            opacity: 0;
            pointer-events: none;
            transition: opacity 0.8s ease;
        }
        .easter-egg-overlay.show {
            opacity: 1;
            pointer-events: auto;
        }
        .easter-egg-text {
            font-size: clamp(1.6em, 6vw, 3.2em);
            font-weight: 900;
            color: #00FF00;
            text-align: center;
            line-height: 1.6;
            text-shadow: 0 0 20px #00FF00, 0 0 60px #00FF00;
            animation: easterGlow 1.5s ease-in-out infinite alternate;
            padding: 0 20px;
        }
        .easter-egg-sub {
            font-size: clamp(0.9em, 2.5vw, 1.3em);
            color: #ff0000;
            margin-top: 30px;
            font-weight: 700;
            text-shadow: 0 0 15px #ff0000;
            animation: warn 0.7s infinite alternate;
        }
        .easter-egg-hint {
            margin-top: 50px;
            font-size: 0.85em;
            color: #444;
            animation: blink 2s infinite alternate;
        }
        @keyframes easterGlow {
            0% { text-shadow: 0 0 15px #00FF00, 0 0 40px #00FF00; }
            100% { text-shadow: 0 0 30px #00FF00, 0 0 80px #00FF00, 0 0 120px #00FF00; }
        }
    </style>
</head>
<body>
    <canvas id="particle-canvas"></canvas>

    <!-- Canvas Nhiễu sóng (Snow) -->
    <canvas id="snow-canvas"></canvas>

    <!-- Trứng phục sinh: Lời nhắn sau khi đếm ngược kết thúc -->
    <div class="easter-egg-overlay" id="easterEgg">
        <div class="easter-egg-text">Tại sao bạn vẫn còn ở đây?!<br>Mau đi chơi đi!!</div>
        <div class="easter-egg-sub">—— Mạt thế đã đến rồi ——</div>
        <div class="easter-egg-hint">[ Nhấn vào bất kỳ đâu để tiếp tục chờ chết ]</div>
    </div>

    <!-- Cửa sổ Popup hệ thống -->
    <div class="popup-overlay" id="popup">
        <div class="popup-window">
            <div class="popup-title">⚠️ C Ả N H B Á O H Ệ T H Ố N G ⚠️</div>
            <div class="popup-text">
                <span class="glitch corrupted" data-rate="0.3">COVID-30</span><br>
                Bạn nhận được một cảnh báo mạt thế từ <span class="warning-blink">kênh không xác định</span><br>
                Thông tin mã hóa phi chính thức, đã tự động đánh chặn và giải mã
            </div>
            <button class="popup-btn" id="closePopup">X E M C H I T I Ế T</button>
        </div>
    </div>

    <!-- Đếm ngược -->
    <div class="countdown-box">
        <div class="countdown" id="countdown">23:59:59</div>
        <div class="countdown-label"><span class="glitch corrupted" data-rate="0.25" id="countdown-label">Đếm ngược COVID-30 Bùng phát</span></div>
    </div>

    <div class="info-card" id="info-card">
        <div class="doom-greeting glitch" id="greeting-text"></div>
        <h1><span class="glitch corrupted" data-rate="0.3">Dự báo</span> <span class="warning-blink corrupted" data-rate="0.25">Tuyệt vọng</span></h1>

        <div class="section">
            <h3><span class="icon icon-warning"></span><span class="glitch corrupted" data-rate="0.25">Tín hiệu</span></h3>
            <p class="corrupted" data-rate="0.3">Thời gian: <strong class="warning-blink">24 giờ trước khi Bùng phát</strong>, chính quyền hoàn toàn làm ngơ, vong linh đã lẻn vào nhân gian</p>
        </div>

        <div class="section">
            <h3><span class="icon icon-virus"></span><span class="glitch corrupted" data-rate="0.35">COVID-30</span></h3>
            <p class="corrupted" data-rate="0.35"><strong>COVID-30</strong>, adrenaline tăng vọt điên cuồng, mất hoàn toàn lý trí, <strong class="warning-blink">tàn sát và cắn xé vô tội vạ</strong>, chạm là lây nhiễm, vô phương cứu chữa, không thể đảo ngược</p>
        </div>

        <div class="section">
            <h3><span class="icon icon-time"></span><span class="glitch corrupted" data-rate="0.25">Đếm ngược</span></h3>
            <p class="corrupted" data-rate="0.3">Thời kỳ ủ bệnh đã đến hồi kết, 24 giờ sau <strong class="warning-blink">bùng phát toàn diện</strong>, văn minh hủy diệt, không ai được cứu, không ai sống sót</p>
        </div>

        <div class="section">
            <h3><span class="icon icon-monitor"></span><span class="glitch corrupted" data-rate="0.3">Cảnh cáo tuyệt vọng</span></h3>
            <ul>
                <li><span class="glitch corrupted" data-rate="0.3">Tránh xa mọi sinh vật sống</span><br><span class="corrupted" data-rate="0.35">Người thân, người lạ, tất cả đều là cỗ máy sát lục</span></li>
                <li><span class="glitch corrupted" data-rate="0.3">Người nhiễm hết cứu</span><br><span class="corrupted" data-rate="0.35">Trốn, chạy, nấp, không có bất kỳ sự cứu rỗi nào</span></li>
                <li><span class="glitch corrupted" data-rate="0.3">Từ bỏ hy vọng</span><br><span class="corrupted" data-rate="0.35">Chính quyền đã thất thủ, thế giới đã đến hồi kết</span></li>
                <li><span class="glitch corrupted" data-rate="0.3">Mạt thế giáng lâm</span><br><span class="corrupted" data-rate="0.35">Bạn là người biết chuyện, cũng là kẻ sắp chết</span></li>
            </ul>
        </div>

        <div class="author">
            <strong class="glitch corrupted" data-rate="0.35">Kẻ gieo rắc tuyệt vọng · Ẩn danh</strong>
        </div>

        <div class="footer">
            <p>Chào mừng đến với <span class="warning-blink">Địa ngục</span>, ở đây không có đội cứu hộ</p>
            <p>Sản xuất bởi cộng đồng Discord <span class="warning-blink">NLKASHEI</span>. Chúc bạn chơi game vui vẻ</p>
        </div>
    </div>

    <script>
        // ==============================================
        // Engine Glitch: Làm hỏng chữ (Thay thế ngẫu nhiên)
        // ==============================================
        const GLITCH_POOL = '█▒░%^&*$#@!◆■□▓▀▄▌▐●∞◇';

        function corruptText(text, rate) {
            const keep = ' ，。、：；！？·—\n「」《》（）0123456789:';
            let out = '';
            let i = 0;
            while (i < text.length) {
                // Giữ lại các ký tự ngắt câu/số
                if (keep.includes(text[i])) { out += text[i]; i++; continue; }
                if (Math.random() < rate) {
                    const r = Math.random();
                    let eat;
                    if (r > 0.75) eat = Math.floor(Math.random() * 5) + 2;
                    else if (r > 0.45) eat = 2;
                    else eat = 1;

                    let consumed = 0;
                    while (consumed < eat && i < text.length && !keep.includes(text[i])) {
                        i++; consumed++;
                    }
                    const gLen = consumed <= 1 ? 1 : (Math.random() < 0.4 ? 1 : 2);
                    for (let g = 0; g < gLen; g++) {
                        out += GLITCH_POOL[Math.floor(Math.random() * GLITCH_POOL.length)];
                    }
                } else {
                    out += text[i]; i++;
                }
            }
            return out;
        }

        // Lưu text gốc và apply Glitch
        function applyCorruption() {
            document.querySelectorAll('.corrupted').forEach(el => {
                const rate = parseFloat(el.dataset.rate || 0.55);
                const walker = document.createTreeWalker(el, NodeFilter.SHOW_TEXT);
                const nodes = [];
                while (walker.nextNode()) nodes.push(walker.currentNode);
                nodes.forEach(node => {
                    if (!node._original) node._original = node.textContent;
                    node.textContent = corruptText(node._original, rate);
                });
            });
        }

        setTimeout(applyCorruption, 100);
        setInterval(applyCorruption, 2500);

        // ==============================================
        // Tắt Popup
        // ==============================================
        const popup = document.getElementById('popup');
        const closePopup = document.getElementById('closePopup');
        closePopup.addEventListener('click', () => {
            popup.style.opacity = 0;
            setTimeout(() => {
                popup.style.display = 'none';
            }, 500);
        });

        // ==============================================
        // 1. Đếm ngược 24h
        // ==============================================
        let totalSeconds = 24 * 60 * 60;
        const countdownEl = document.getElementById('countdown');
        const countdownLabel = document.getElementById('countdown-label');
        let easterEggTriggered = false;

        function updateCountdown() {
            if (totalSeconds <= 0) {
                countdownEl.textContent = "00:00:00";
                countdownEl.style.animation = 'none';
                countdownEl.style.color = '#00FF00';
                countdownEl.style.textShadow = '0 0 20px #00FF00, 0 0 40px #00FF00';
                countdownLabel.textContent = 'COVID-30 Đã bùng phát';
                countdownLabel.style.color = '#ff0000';
                if (!easterEggTriggered) {
                    easterEggTriggered = true;
                    triggerEasterEgg();
                }
                return;
            }
            const hours = String(Math.floor(totalSeconds / 3600)).padStart(2, '0');
            const minutes = String(Math.floor((totalSeconds % 3600) / 60)).padStart(2, '0');
            const seconds = String(totalSeconds % 60).padStart(2, '0');
            countdownEl.textContent = `${hours}:${minutes}:${seconds}`;
            totalSeconds--;
        }
        updateCountdown();
        setInterval(updateCountdown, 1000);

        // ==============================================
        // 2. Chữ chạy (Greeting)
        // ==============================================
        const greetingElement = document.getElementById('greeting-text');
        const greetings = [
            'COVID-30 ập đến',
            'Chạm là lây nhiễm, không ai được cứu',
            'Chính quyền làm ngơ, toàn viên chôn cùng',
            'Sát lục · Mất kiểm soát · Hủy diệt',
            '24 giờ nữa, thế giới biến mất'
        ];
        let currentGreetingIndex = 0;

        function changeGreeting() {
            greetingElement.style.opacity = 0;
            setTimeout(() => {
                currentGreetingIndex = (currentGreetingIndex + 1) % greetings.length;
                greetingElement.textContent = corruptText(greetings[currentGreetingIndex], 0.3);
                greetingElement.style.opacity = 1;
            }, 350);
        }
        greetingElement.textContent = corruptText(greetings[0], 0.3);
        setInterval(changeGreeting, 3800);

        // ==============================================
        // 3. Canvas Hạt máu
        // ==============================================
        const canvas = document.getElementById('particle-canvas');
        const ctx = canvas.getContext('2d');
        let particles = [];

        function setupCanvas() {
            canvas.width = window.innerWidth;
            canvas.height = window.innerHeight;
        }
        setupCanvas();
        window.addEventListener('resize', setupCanvas);

        function createParticle() {
            return {
                x: Math.random() * canvas.width,
                y: Math.random() * canvas.height,
                radius: Math.random() * 1.8,
                color: `hsla(0, 100%, 45%, ${Math.random() * 0.6})`,
                speedX: Math.random() * 0.25 - 0.12,
                speedY: Math.random() * 0.25 - 0.12,
                life: 1
            };
        }
        for (let i = 0; i < 130; i++) particles.push(createParticle());

        function loop() {
            requestAnimationFrame(loop);
            ctx.globalCompositeOperation = 'destination-out';
            ctx.fillStyle = 'rgba(0, 0, 0, 0.12)';
            ctx.fillRect(0, 0, canvas.width, canvas.height);
            ctx.globalCompositeOperation = 'lighter';

            particles.forEach((p, index) => {
                p.x += p.speedX;
                p.y += p.speedY;
                p.life -= 0.0025;
                if (p.life <= 0) {
                    particles.splice(index, 1, createParticle());
                    return;
                }
                ctx.beginPath();
                ctx.arc(p.x, p.y, p.radius, 0, Math.PI * 2);
                ctx.fillStyle = p.color;
                ctx.fill();
            });
        }
        loop();

        // ==============================================
        // 4. Hiệu ứng nghiêng chuột
        // ==============================================
        const card = document.getElementById('info-card');
        const sensitivity = 18;

        card.addEventListener('mousemove', (e) => {
            const { clientX, clientY } = e;
            const { left, top, width, height } = card.getBoundingClientRect();
            const x = clientX - left;
            const y = clientY - top;
            const rotateY = sensitivity * ((x - width / 2) / width);
            const rotateX = -sensitivity * ((y - height / 2) / height);
            card.style.transform = `perspective(1000px) rotateX(${rotateX}deg) rotateY(${rotateY}deg)`;
        });

        card.addEventListener('mouseleave', () => {
            card.style.transform = 'perspective(1000px) rotateX(0deg) rotateY(0deg)';
        });

        // ==============================================
        // 5. Snow Canvas (Nhiễu màn hình)
        // ==============================================
        const snowCanvas = document.getElementById('snow-canvas');
        const snowCtx = snowCanvas.getContext('2d');

        function resizeSnow() {
            snowCanvas.width = Math.ceil(window.innerWidth / 3);
            snowCanvas.height = Math.ceil(window.innerHeight / 3);
            snowCanvas.style.width = '100vw';
            snowCanvas.style.height = '100vh';
            snowCanvas.style.imageRendering = 'pixelated';
        }
        resizeSnow();
        window.addEventListener('resize', resizeSnow);

        function drawSnow() {
            const w = snowCanvas.width;
            const h = snowCanvas.height;
            const imgData = snowCtx.createImageData(w, h);
            const data = imgData.data;
            for (let i = 0; i < data.length; i += 4) {
                const v = Math.random() * 255;
                const colorShift = Math.random();
                if (colorShift < 0.08) {
                    data[i] = v * 1.2;
                    data[i + 1] = v * 0.3;
                    data[i + 2] = v * 0.2;
                } else if (colorShift < 0.14) {
                    data[i] = v * 0.2;
                    data[i + 1] = v * 1.2;
                    data[i + 2] = v * 0.3;
                } else {
                    data[i] = v;
                    data[i + 1] = v;
                    data[i + 2] = v;
                }
                data[i + 3] = Math.random() * 120 + 40; 
            }
            snowCtx.putImageData(imgData, 0, 0);

            const barCount = Math.floor(Math.random() * 4) + 1;
            for (let b = 0; b < barCount; b++) {
                const y = Math.floor(Math.random() * h);
                const barH = Math.floor(Math.random() * 3) + 1;
                snowCtx.fillStyle = `rgba(255,255,255,${0.1 + Math.random() * 0.2})`;
                snowCtx.fillRect(0, y, w, barH);
            }
        }

        let snowActive = false;
        let snowRafId = null;

        function snowLoop() {
            if (!snowActive) return;
            drawSnow();
            snowRafId = requestAnimationFrame(snowLoop);
        }

        function triggerSnowGlitch() {
            const duration = 80 + Math.random() * 270;
            snowActive = true;
            snowCanvas.classList.add('active');
            snowLoop();

            setTimeout(() => {
                snowActive = false;
                snowCanvas.classList.remove('active');
                if (snowRafId) cancelAnimationFrame(snowRafId);
                snowCtx.clearRect(0, 0, snowCanvas.width, snowCanvas.height);
            }, duration);

            const nextDelay = 2500 + Math.random() * 4500;
            setTimeout(triggerSnowGlitch, nextDelay + duration);
        }
        setTimeout(triggerSnowGlitch, 1500);

        // ==============================================
        // 6. Trứng phục sinh sau khi đếm ngược
        // ==============================================
        function triggerEasterEgg() {
            snowActive = true;
            snowCanvas.classList.add('active');
            snowLoop();

            setTimeout(() => {
                snowActive = false;
                snowCanvas.classList.remove('active');
                if (snowRafId) cancelAnimationFrame(snowRafId);
                snowCtx.clearRect(0, 0, snowCanvas.width, snowCanvas.height);

                const easterEgg = document.getElementById('easterEgg');
                easterEgg.classList.add('show');

                easterEgg.addEventListener('click', () => {
                    easterEgg.classList.remove('show');
                });
            }, 1500);
        }

        async function switchToSecondGreeting() {
            if (typeof getChatMessages !== 'undefined' && typeof setChatMessage !== 'undefined') {
                try {
                    const msgs = await getChatMessages(0, { include_swipe: true });
                    if (msgs && msgs[0] && msgs[0].swipes && msgs[0].swipes.length > 1) {
                        const targetSwipeContent = msgs[0].swipes[1];
                        setChatMessage(targetSwipeContent, 0, {
                            swipe_id: 1,
                            refresh: 'display_and_render_current'
                        });
                    } else {
                        alert('Chưa phát hiện Lời mở đầu thứ 2. Hãy đảm bảo bạn đã cấu hình tùy chọn Alternate Greetings.');
                    }
                } catch (err) {
                    console.error(err);
                    alert('Chuyển hướng thất bại, vui lòng kiểm tra lỗi trong Console.');
                }
            } else if (typeof triggerSlash !== 'undefined') {
                triggerSlash('/send Nhấn để Tạo nhân vật');
            } else {
                alert('Chưa phát hiện lệnh trợ lý trong môi trường hiện tại.');
            }
        }
    </script>

