    }

    .preset-hint {
        color: var(--text-secondary);
        font-size: 0.95em;
        opacity: 0.5;
        font-style: italic;
    }

    /* ===== Chọn Mô hình Hành vi ===== */
    .behavior-selector {
        display: flex;
        gap: 10px;
        width: 100%;
    }

    .behavior-card {
        flex: 1;
        background: var(--input-bg);
        border: 2px solid var(--input-border);
        border-radius: 6px;
        padding: 8px 10px;
        cursor: pointer;
        text-align: center;
        transition: all 0.25s ease;
        user-select: none;
        position: relative;
    }

    .behavior-card:hover { border-color: var(--accent-orange); }

    .behavior-card.selected { border-color: var(--accent-orange); background: rgba(249,115,22,0.08); box-shadow: 0 0 12px rgba(249,115,22,0.15); }

    .behavior-card .behavior-icon { font-size: 1.4em; margin-bottom: 2px; }

    .behavior-card .behavior-name {
        font-family: var(--font-mono);
        font-size: 0.9em;
        font-weight: 700;
        color: var(--text-secondary);
        margin-bottom: 3px;
    }

    .behavior-card.selected .behavior-name { color: var(--accent-orange); text-shadow: 0 0 6px rgba(249,115,22,0.3); }

    .behavior-card .behavior-desc {
        font-size: 1em;
        color: var(--text-secondary);
        line-height: 1.4;
        opacity: 0.7;
        font-style: italic;
    }

    .behavior-card.selected .behavior-desc { opacity: 1; }

    .behavior-card .recommend-badge {
        position: absolute;
        top: -8px;
        right: -6px;
        background: var(--accent-orange);
        color: #fff;
        font-size: 0.65em;
        padding: 1px 5px;
        border-radius: 3px;
        font-weight: 700;
        font-style: normal;
    }

    .behavior-hint {
        font-size: 0.95em;
        color: var(--accent-orange);
        opacity: 0.8;
        margin-top: 4px;
        animation: hintPulse 1.5s ease-in-out infinite;
    }

    @keyframes hintPulse {
        0%, 100% { opacity: 0.5; }
        50% { opacity: 1; }
    }

    body.light-mode .behavior-card { background: #fff; }
    body.light-mode .behavior-card.selected { background: rgba(249,115,22,0.06); border-color: #ea580c; }
    body.light-mode .behavior-card.selected .behavior-name { color: #ea580c; text-shadow: none; }

    @media (max-width: 600px) {
        .behavior-selector { flex-direction: column; }
    }

    /* ===== Chế độ Đặc điểm ===== */
    .mode-selector {
        display: flex;
        gap: 10px;
        width: 100%;
        grid-column: 1 / -1;
        margin-bottom: 6px;
    }

    .mode-card {
        flex: 1;
        background: var(--input-bg);
        border: 2px solid var(--input-border);
        border-radius: 6px;
        padding: 12px 10px;
        cursor: pointer;
        text-align: center;
        transition: all 0.25s ease;
        user-select: none;
    }

    .mode-card:hover { border-color: var(--accent-cyan); }

    .mode-card.selected-god { border-color: var(--accent-yellow); background: rgba(234,179,8,0.08); }
    .mode-card.selected-normal { border-color: var(--accent-cyan); background: rgba(6,182,212,0.08); }
    .mode-card.selected-hard { border-color: var(--accent-red); background: rgba(239,68,68,0.08); }

    .mode-card .mode-name {
        font-family: var(--font-mono);
        font-size: 1em;
        font-weight: 700;
        margin-bottom: 4px;
    }

    .mode-card.selected-god .mode-name { color: var(--accent-yellow); }
    .mode-card.selected-normal .mode-name { color: var(--accent-cyan); }
    .mode-card.selected-hard .mode-name { color: var(--accent-red); }

    .mode-card .mode-desc {
        font-size: 0.95em;
        color: var(--text-secondary);
        line-height: 1.4;
    }

    /* ===== Random Đặc điểm ===== */
    .random-trait-bar {
        grid-column: 1 / -1;
        display: flex;
        align-items: center;
        gap: 12px;
        margin-bottom: 4px;
    }

    .random-trait-btn {
        background: transparent;
        border: 1px solid var(--accent-cyan);
        color: var(--accent-cyan);
        padding: 8px 20px;
        font-family: var(--font-mono);
        font-size: 0.95em;
        cursor: pointer;
        border-radius: 4px;
        transition: all 0.25s ease;
        white-space: nowrap;
    }

    .random-trait-btn:hover:not(:disabled) { background: rgba(6,182,212,0.12); box-shadow: 0 0 10px rgba(6,182,212,0.2); }

    .random-trait-btn:disabled { opacity: 0.35; cursor: not-allowed; }

    .random-trait-btn:active:not(:disabled) { transform: scale(0.96); }

    .random-hint {
        font-family: var(--font-mono);
        font-size: 0.95em;
        color: var(--text-secondary);
    }

    /* ===== Hiển thị Điểm ===== */
    .points-bar {
        grid-column: 1 / -1;
        display: flex;
        align-items: center;
        justify-content: space-between;
        background: rgba(0,0,0,0.4);
        border: 1px solid var(--border-dim);
        border-radius: 6px;
        padding: 10px 16px;
        margin-bottom: 6px;
    }

    .points-label {
        font-family: var(--font-mono);
        font-size: 0.95em;
        color: var(--text-secondary);
    }

    .points-value {
        font-family: var(--font-mono);
        font-size: 1.4em;
        font-weight: 700;
        transition: color 0.3s;
    }

    .points-value.positive { color: var(--accent-green); }
    .points-value.zero { color: var(--accent-yellow); }
    .points-value.negative { color: var(--accent-red); animation: shake 0.4s; }

    @keyframes shake {
        0%, 100% { transform: translateX(0); }
        25% { transform: translateX(-4px); }
        75% { transform: translateX(4px); }
    }

    /* ===== Tag Đặc điểm ===== */
    .trait-section {
        grid-column: 1 / -1;
        margin-bottom: 8px;
    }

    .trait-section-title {
        font-family: var(--font-mono);
        font-size: 0.9em;
        color: var(--text-secondary);
        margin-bottom: 8px;
        display: flex;
        align-items: center;
        gap: 6px;
    }

    .trait-section-title .pos { color: var(--accent-green); }
    .trait-section-title .neg { color: var(--accent-red); }

    .tag-selector {
        display: flex;
        flex-wrap: wrap;
        gap: 7px;
    }

    .tag-option {
        background: var(--input-bg);
        border: 1px solid var(--input-border);
        color: var(--text-secondary);
        padding: 4px 10px;
        border-radius: 3px;
        cursor: pointer;
        font-family: var(--font-mono);
        font-size: 0.82em;
        transition: all 0.2s ease;
        user-select: none;
        display: inline-flex;
        align-items: center;
        gap: 4px;
        position: relative;
    }

    .tag-option .cost {
        font-size: 0.78em;
        opacity: 0.6;
    }

    .tag-option:hover { border-color: var(--accent-cyan); color: var(--text-primary); }

    .tag-option.selected.positive-trait {
        background: var(--tag-green);
        color: var(--tag-green-text);
        border-color: var(--tag-green-border);
        font-weight: bold;
    }

    .tag-option.selected.negative-trait {
        background: var(--tag-red);
        color: var(--tag-red-text);
        border-color: var(--tag-red-border);
        font-weight: bold;
    }

    .tag-option.disabled {
        opacity: 0.3;
        cursor: not-allowed;
        pointer-events: none;
    }

    /* ===== Tooltip Đặc điểm ===== */
    .trait-tooltip {
        position: fixed;
        z-index: 99999;
        background: rgba(17, 17, 22, 0.97);
        border: 1px solid var(--border-glow);
        border-radius: 6px;
        padding: 10px 14px;
        max-width: min(300px, calc(100vw - 20px));
        min-width: 160px;
        font-family: var(--font-ui);
        font-size: 0.88em;
        color: var(--text-primary);
        line-height: 1.6;
        word-break: break-word;
        box-shadow: 0 0 20px rgba(239,68,68,0.2), 0 4px 20px rgba(0,0,0,0.6);
        pointer-events: none;
        opacity: 0;
        transition: opacity 0.2s;
    }

    .trait-tooltip.visible { opacity: 1; }

    .trait-tooltip .tt-name {
        font-family: var(--font-mono);
        font-weight: 700;
        margin-bottom: 4px;
    }

    .trait-tooltip .tt-name.pos-name { color: var(--accent-green); }
    .trait-tooltip .tt-name.neg-name { color: var(--accent-red); }

    .trait-tooltip .tt-cost {
        font-family: var(--font-mono);
        font-size: 0.8em;
        color: var(--text-secondary);
        margin-bottom: 6px;
    }

    .trait-tooltip .tt-desc {
        color: var(--text-secondary);
    }

    /* ===== Modal hệ thống ===== */
    .builtin-modal-overlay {
        position: fixed;
        top: 0; left: 0; right: 0; bottom: 0;
        background: rgba(0,0,0,0.65);
        display: flex;
        align-items: center;
        justify-content: center;
        z-index: 99999;
        animation: modalFadeIn 0.2s ease;
    }

    @keyframes modalFadeIn { from { opacity: 0; } to { opacity: 1; } }

    .builtin-modal {
        background: var(--bg-card);
        border: 1px solid var(--accent-red);
        border-radius: 8px;
        padding: 28px 36px;
        max-width: 380px;
        text-align: center;
        box-shadow: 0 0 30px rgba(255,55,55,0.25), 0 0 60px rgba(255,55,55,0.08);
        animation: modalSlideIn 0.25s ease;
    }

    @keyframes modalSlideIn { from { transform: translateY(-20px); opacity: 0; } to { transform: translateY(0); opacity: 1; } }

    .builtin-modal .modal-icon {
        font-size: 2.4em;
        margin-bottom: 10px;
    }

    .builtin-modal .modal-title {
        font-family: var(--font-mono);
        font-size: 1.15em;
        font-weight: 700;
        color: var(--accent-red);
        margin-bottom: 8px;
    }

    .builtin-modal .modal-msg {
        font-size: 0.92em;
        color: var(--text-secondary);
        margin-bottom: 20px;
        line-height: 1.6;
    }

    .builtin-modal .modal-btn {
        background: transparent;
        border: 1px solid var(--accent-red);
        color: var(--accent-red);
        padding: 8px 32px;
        font-family: var(--font-mono);
        font-size: 0.9em;
        cursor: pointer;
        border-radius: 4px;
        transition: all 0.2s;
    }

    .builtin-modal .modal-btn:hover { background: rgba(255,55,55,0.12); }

    /* ===== Đặc điểm Tùy chỉnh (Chỉ có ở chế độ Sảng văn) ===== */
    .custom-trait-section {
        grid-column: 1 / -1;
        border: 1px dashed rgba(234,179,8,0.3);
        border-radius: 6px;
        padding: 12px;
        background: rgba(234,179,8,0.03);
        display: none;
    }

    .custom-trait-section.visible { display: block; }

    .custom-trait-section .ct-title {
        font-family: var(--font-mono);
        font-size: 0.9em;
        color: var(--accent-yellow);
        margin-bottom: 10px;
    }

    .custom-trait-row {
        display: flex;
        gap: 8px;
        align-items: flex-end;
    }

    .custom-trait-row .form-group { flex: 1; }

    .add-trait-btn {
        background: transparent;
        border: 1px solid var(--accent-yellow);
        color: var(--accent-yellow);
        padding: 9px 16px;
        font-family: var(--font-mono);
        font-size: 0.85em;
        cursor: pointer;
        border-radius: 4px;
        transition: all 0.2s ease;
        white-space: nowrap;
        height: fit-content;
    }

    .add-trait-btn:hover { background: rgba(234,179,8,0.12); }

    .custom-traits-list {
        display: flex;
        flex-wrap: wrap;
        gap: 6px;
        margin-top: 8px;
        min-height: 10px;
    }

    .custom-trait-chip {
        display: inline-flex;
        align-items: center;
        gap: 5px;
        padding: 3px 10px;
        border-radius: 3px;
        font-family: var(--font-mono);
        font-size: 0.8em;
        cursor: pointer;
        transition: all 0.2s ease;
        background: rgba(234,179,8,0.1);
        color: var(--accent-yellow);
        border: 1px solid rgba(234,179,8,0.3);
    }

    .custom-trait-chip .remove-x {
        opacity: 0.5;
        font-weight: bold;
    }

    .custom-trait-chip:hover .remove-x { opacity: 1; }

    .custom-special-row {
        margin-top: 10px;
        padding-top: 8px;
        border-top: 1px dashed rgba(234,179,8,0.15);
    }

    .custom-special-label {
        font-family: var(--font-mono);
        font-size: 0.78em;
        color: var(--text-secondary);
        letter-spacing: 0.5px;
        display: block;
        margin-bottom: 6px;
    }

    .custom-special-inputs {
        display: flex;
        gap: 8px;
        flex-wrap: wrap;
    }

    .custom-special-input-group {
        display: flex;
        flex-direction: column;
        align-items: center;
        flex: 1;
        min-width: 44px;
    }

    .custom-special-input-group label {
        font-family: var(--font-mono);
        font-size: 0.7em;
        color: var(--accent-cyan);
        font-weight: 700;
        margin-bottom: 2px;
    }

    .custom-special-input-group input {
        width: 100%;
        background: var(--input-bg);
        border: 1px solid var(--input-border);
        color: var(--text-primary);
        padding: 4px 2px;
        border-radius: 3px;
        font-family: var(--font-mono);
        font-size: 0.9em;
        text-align: center;
        -moz-appearance: textfield;
    }

    .custom-special-input-group input::-webkit-inner-spin-button,
    .custom-special-input-group input::-webkit-outer-spin-button {
        -webkit-appearance: none;
        margin: 0;
    }

    .custom-special-input-group input:focus {
        outline: none;
        border-color: var(--accent-yellow);
        box-shadow: 0 0 6px rgba(234,179,8,0.3);
    }

    .custom-trait-chip .special-tag {
        font-size: 0.85em;
        font-weight: 700;
    }

    .custom-trait-chip .special-tag.pos { color: var(--accent-green); }
    .custom-trait-chip .special-tag.neg { color: var(--accent-red); }

    /* ===== Danh sách Đặc điểm đã chọn ===== */
    .selected-traits {
        grid-column: 1 / -1;
        display: flex;
        flex-wrap: wrap;
        gap: 6px;
        min-height: 30px;
        padding: 6px 0;
    }

    .selected-trait-chip {
        display: inline-flex;
        align-items: center;
        gap: 5px;
        padding: 3px 10px;
        border-radius: 3px;
        font-family: var(--font-mono);
        font-size: 0.8em;
        cursor: pointer;
        transition: all 0.2s ease;
    }

    .selected-trait-chip.pos {
        background: var(--tag-green);
        color: var(--tag-green-text);
        border: 1px solid var(--tag-green-border);
    }

    .selected-trait-chip.neg {
        background: var(--tag-red);
        color: var(--tag-red-text);
        border: 1px solid var(--tag-red-border);
    }

    .selected-trait-chip .remove-x {
        opacity: 0.5;
        font-weight: bold;
    }

    .selected-trait-chip:hover .remove-x { opacity: 1; }

    /* ===== Nút Xác nhận ===== */
    .confirm-button {
        background: var(--accent-red);
        border: 1px solid rgba(239,68,68,0.6);
        color: #fff;
        padding: 12px 25px;
        font-family: var(--font-mono);
        font-size: 1.5em;
        cursor: pointer;
        transition: all 0.3s ease;
        border-radius: 5px;
        box-shadow: 0 0 15px rgba(239,68,68,0.4);
        letter-spacing: 2px;
    }

    .confirm-button:hover {
        background: #dc2626;
        box-shadow: 0 0 25px rgba(239,68,68,0.6);
        transform: scale(1.03);
    }

    .confirm-button:disabled {
        opacity: 0.4;
        cursor: not-allowed;
        transform: none;
        box-shadow: none;
    }

    .error-msg {
        grid-column: 1 / -1;
        color: var(--accent-red);
        font-family: var(--font-mono);
        font-size: 0.85em;
        text-align: center;
        min-height: 20px;
    }

    /* ===== Tổng quan S.P.E.C.I.A.L. ===== */
    .special-overview {
        grid-column: 1 / -1;
        background: rgba(0,0,0,0.5);
        border: 1px solid var(--accent-red);
        border-radius: 8px;
        padding: 16px 20px;
        margin-top: 8px;
        box-shadow: 0 0 12px rgba(239,68,68,0.1);
    }

    .special-title {
        font-family: var(--font-mono);
        font-size: 1em;
        color: var(--accent-red);
        letter-spacing: 1.5px;
        margin-bottom: 12px;
        text-align: center;
    }

    .special-grid {
        display: grid;
        grid-template-columns: repeat(7, 1fr);
        gap: 8px;
    }

    .special-item {
        text-align: center;
        background: var(--input-bg);
        border: 1px solid var(--input-border);
        border-radius: 6px;
        padding: 8px 4px;
        transition: all 0.3s ease;
    }

    .special-item.boosted {
        border-color: var(--accent-green);
        box-shadow: 0 0 8px rgba(34,197,94,0.2);
    }

    .special-item.reduced {
        border-color: var(--accent-red);
        box-shadow: 0 0 8px rgba(239,68,68,0.2);
    }

    .special-item.neutral {
        border-color: var(--input-border);
    }

    .special-label {
        font-family: var(--font-mono);
        font-size: 0.75em;
        color: var(--text-secondary);
        letter-spacing: 1px;
        margin-bottom: 4px;
    }

    .special-letter {
        font-family: var(--font-mono);
        font-size: 1.3em;
        font-weight: 700;
        margin-bottom: 2px;
    }

    .special-item.boosted .special-letter { color: var(--accent-green); text-shadow: 0 0 6px rgba(34,197,94,0.4); }
    .special-item.reduced .special-letter { color: var(--accent-red); text-shadow: 0 0 6px rgba(239,68,68,0.4); }
    .special-item.neutral .special-letter { color: var(--text-secondary); }

    .special-value {
        font-family: var(--font-mono);
        font-size: 1.3em;
        font-weight: 700;
    }

    .special-item.boosted .special-value { color: var(--accent-green); text-shadow: 0 0 6px rgba(34,197,94,0.4); }
    .special-item.reduced .special-value { color: var(--accent-red); text-shadow: 0 0 6px rgba(239,68,68,0.4); }
    .special-item.neutral .special-value { color: var(--text-secondary); }

    .special-delta {
        font-family: var(--font-mono);
        font-size: 0.78em;
        margin-top: 2px;
    }

    .special-delta.positive { color: var(--accent-green); }
    .special-delta.negative { color: var(--accent-red); }
    .special-delta.zero { color: var(--text-secondary); opacity: 0.4; }

    .special-bar-track {
        width: 100%;
        height: 4px;
        background: rgba(255,255,255,0.05);
        border-radius: 2px;
        margin-top: 4px;
        position: relative;
        overflow: hidden;
    }

    .special-bar-zero {
        position: absolute;
        left: 50%;
        top: 0;
        width: 1px;
        height: 100%;
        background: rgba(255,255,255,0.15);
    }

    .special-bar-fill {
        position: absolute;
        top: 0;
        height: 100%;
        border-radius: 2px;
        transition: all 0.3s ease;
    }

    .special-item.boosted .special-bar-fill { background: var(--accent-green); }
    .special-item.reduced .special-bar-fill { background: var(--accent-red); }
    .special-item.neutral .special-bar-fill { background: transparent; }

    /* ===== Nút đổi Theme ===== */
    .theme-toggle {
        position: fixed;
        top: 16px;
        right: 16px;
        z-index: 100000;
        width: 48px;
        height: 48px;
        border-radius: 50%;
        border: 2px solid var(--border-dim);
        background: var(--bg-card);
        color: var(--text-primary);
        font-size: 1.3em;
        cursor: grab;
        display: flex;
        align-items: center;
        justify-content: center;
        transition: border-color 0.3s ease, box-shadow 0.3s ease, background 0.3s ease;
        box-shadow: 0 2px 12px rgba(0,0,0,0.3);
        user-select: none;
        touch-action: none;
    }

    .theme-toggle:active { cursor: grabbing; }

    .theme-toggle.dragging {
        transition: none;
        cursor: grabbing;
        box-shadow: 0 4px 20px rgba(0,0,0,0.4);
    }

    .theme-toggle:hover:not(.dragging) {
        border-color: var(--accent-cyan);
        box-shadow: 0 0 16px rgba(6,182,212,0.3);
    }

    /* ===== Giao diện Sáng ===== */
    body.light-mode {
        --bg-deep: #f5f5f7;
        --bg-panel: #ffffff;
        --bg-card: #ffffff;
        --border-dim: #d1d5db;
        --border-glow: #b91c1c;
        --text-primary: #1f2937;
        --text-secondary: #6b7280;
        --text-bright: #111827;
        --accent-red: #dc2626;
        --accent-red-dim: #991b1b;
        --accent-green: #16a34a;
        --accent-blue: #2563eb;
        --accent-yellow: #d97706;
        --accent-orange: #ea580c;
        --accent-cyan: #0891b2;
        --input-bg: #f9fafb;
        --input-border: #d1d5db;
        --tag-red: rgba(220, 38, 38, 0.08);
        --tag-red-text: #dc2626;
        --tag-red-border: rgba(220, 38, 38, 0.25);
        --tag-green: rgba(22, 163, 74, 0.08);
        --tag-green-text: #16a34a;
        --tag-green-border: rgba(22, 163, 74, 0.25);
        --tag-cyan: rgba(8, 145, 178, 0.08);
        --tag-cyan-text: #0891b2;
        --tag-cyan-border: rgba(8, 145, 178, 0.25);
        --gold-color: #b8860b;
    }

    body.light-mode::before { display: none; }

    body.light-mode::after { display: none; }

