    body.light-mode .form-group label { color: var(--accent-cyan); }

    body.light-mode .nat-card.selected {
        border-color: var(--accent-cyan);
        background: rgba(8,145,178,0.08);
        box-shadow: 0 0 12px rgba(8,145,178,0.15);
