    @media (max-width: 768px) {
        .title { font-size: 1.8em; }
        .start-text { font-size: 0.9em; }
        .start-button { --size: 75px; }
        .char-form { grid-template-columns: 1fr; }
        .behavior-selector { flex-direction: column; }
        .mode-selector { flex-direction: column; }
        .custom-trait-row { flex-direction: column; }
        .custom-special-inputs { gap: 5px; }
        .custom-special-input-group { min-width: 38px; }
        .special-grid { grid-template-columns: repeat(4, 1fr); }
        .nationality-selector { gap: 6px; }
        .nat-card { min-width: calc(33% - 6px); padding: 10px 6px; }
        .nat-card .nat-flag { font-size: 1.5em; margin-bottom: 4px; }
        .nat-card .nat-name { font-size: 0.8em; }
        .add-trait-btn { width: 100%; margin-top: 4px; }
        .custom-trait-row .form-group { min-width: 0; }
        .custom-special-row { overflow-x: auto; -webkit-overflow-scrolling: touch; }
        .tag-option { font-size: 0.78em; padding: 4px 8px; }
        .form-group input, .form-group select { font-size: 0.9em; }
        .divider-title { font-size: 0.95em; }
        .ct-title { font-size: 0.85em; }
        #custom-trait-hint { font-size: 0.8em !important; }
        .preset-drawer { padding: 6px 8px; gap: 5px; }
        .preset-pill { font-size: 0.76em; padding: 4px 10px 4px 9px; }
        .phase-btn .phase-tip { min-width: 200px; max-width: 280px; font-size: 0.85em; left: 50%; transform: translateX(-50%); }
        .phase-btn:first-child .phase-tip { left: 0; transform: none; }
        .phase-btn:first-child .phase-tip::before { left: 20px; transform: rotate(45deg); }
        .phase-btn:last-child .phase-tip { left: auto; right: 0; transform: none; }
        .phase-btn:last-child .phase-tip::before { left: auto; right: 16px; transform: rotate(45deg); }
        .phase-desc { font-size: 0.82em; }
