    /* ===== MVU Thông báo Đồng bộ ===== */
    .mvu-sync-indicator {
        position: fixed;
        bottom: 16px;
        left: 16px;
        z-index: 100000;
        background: rgba(34, 197, 94, 0.15);
        border: 1px solid rgba(34, 197, 94, 0.4);
        color: #22c55e;
        font-family: var(--font-mono);
        font-size: 0.78em;
        padding: 4px 12px;
        border-radius: 4px;
        opacity: 0;
        transition: opacity 0.3s;
        pointer-events: none;
    }
    .mvu-sync-indicator.visible { opacity: 1; }
    body.light-mode .mvu-sync-indicator {
        background: rgba(22, 163, 74, 0.1);
        border-color: rgba(22, 163, 74, 0.3);
        color: #16a34a;
    }
</style>
</head>
<body>
    <!-- disable-default-loading -->
    <button class="theme-toggle" id="theme-toggle" title="Chuyển đổi Sáng/Tối">🌙</button>
    <div id="background-particles"></div>

    <!-- Bong bóng tooltip Đặc điểm -->
    <div class="trait-tooltip" id="trait-tooltip"></div>

    <!-- Modal nội bộ -->
    <div class="builtin-modal-overlay" id="builtin-modal" style="display:none;">
        <div class="builtin-modal">
            <div class="modal-icon">⚠️</div>
            <div class="modal-title" id="modal-title">Thông báo</div>
            <div class="modal-msg" id="modal-msg"></div>
            <button class="modal-btn" id="modal-btn">Xác nhận</button>
        </div>
    </div>

    <!-- Thông báo Đồng bộ MVU -->
    <div class="mvu-sync-indicator" id="mvu-sync-indicator">MVU ✓ Đã đồng bộ</div>

    <!-- ===== Trang Khởi đầu ===== -->
    <div class="screen active" id="start-screen">
        <div class="title">☠️ Hồ Sơ Người Sống Sót</div>
        <p class="start-text">Tận thế giáng xuống, trật tự sụp đổ. Bạn là ai?<br>Định hình danh tính, tính cách, xuất thân và lựa chọn đặc điểm của bạn...<br>Nơi vùng đất hoang tàn này, mọi lợi thế đều phải trả bằng một cái giá tương xứng.</p>
        <div class="start-button" id="start-button">
            <span class="start-button-text">Tạo Hồ Sơ</span>
        </div>
    </div>

    <!-- ===== Trang Định nghĩa Nhân vật ===== -->
    <div class="screen" id="char-screen">
        <div class="form-title">☠️ Thiết Lập Hồ Sơ</div>

        <div class="char-form" id="main-form">

            <!-- ===== Danh tính cơ bản ===== -->
            <h3 class="divider-title">◈ Danh Tính Cơ Bản</h3>

            <div class="form-group">
                <label for="c-name">Họ Tên</label>
                <input type="text" id="c-name" placeholder="Tên hoặc biệt danh của bạn">
            </div>
            <div class="form-group">
                <label for="c-gender">Giới Tính</label>
                <input type="text" id="c-gender" placeholder="Nam/Nữ/Khác">
            </div>
            <div class="form-group">
                <label for="c-age">Tuổi</label>
                <input type="number" id="c-age" placeholder="Nhập số" min="1" max="120">
            </div>
            <div class="form-group">
                <label>Giai Đoạn Cốt Truyện</label>
                <div class="phase-selector" id="phase-selector">
                    <div class="phase-btn selected" data-val="Thời kỳ trật tự">Thời kỳ trật tự<span class="phase-recommend">Gợi ý</span>
                        <div class="phase-tip">
                            <div class="tip-time">08:00 Ngày 23/08/2030</div>
                            <div class="tip-desc">Trật tự xã hội vẫn còn, mới chỉ phong tỏa do dịch bệnh</div>
                        </div>
                    </div>
                    <div class="phase-btn" data-val="Thời kỳ bùng phát">Thời kỳ bùng phát
                        <div class="phase-tip">
                            <div class="tip-time">14:00 Ngày 24/08/2030</div>
                            <div class="tip-desc">Người nhiễm tràn lan, trật tự sụp đổ, nhưng điện nước vẫn còn</div>
                        </div>
                    </div>
                    <div class="phase-btn" data-val="Thời kỳ tận thế">Thời kỳ tận thế
                        <div class="phase-tip">
                            <div class="tip-time">08:00 Ngày 26/08/2030</div>
                            <div class="tip-desc">Xuất hiện người nhiễm biến thể, mất điện nước mạng, trật tự sụp đổ hoàn toàn</div>
                        </div>
                    </div>
                </div>
            </div>
            <div class="phase-desc" id="phase-desc">
                <span class="desc-time">08:00 Ngày 23/08/2030</span>
                <span class="desc-text">Trật tự xã hội vẫn còn, mới chỉ phong tỏa do dịch bệnh</span>
            </div>
            <div class="form-group full-width">
                <label>Quốc Tịch (Ảnh hưởng điểm xuất phát)<span id="nat-hint" style="color:var(--accent-red); font-size:0.85em; margin-left:6px;">⚠ Vui lòng chọn Quốc tịch</span></label>
                <div class="nationality-selector" id="nationality-selector">
                    <div class="nat-card updated unselected-pulse" data-val="Trung Quốc">
                        <div class="nat-flag">🇨🇳</div>
                        <div class="nat-name">Trung Quốc</div>
                        <div class="nat-badge">Đã cập nhật</div>
                    </div>
                    <div class="nat-card updated unselected-pulse" data-val="Mỹ">
                        <div class="nat-flag">🇺🇸</div>
                        <div class="nat-name">Mỹ</div>
                        <div class="nat-badge">Đã cập nhật</div>
                    </div>
                    <div class="nat-card updated unselected-pulse" data-val="Nhật Bản">
                        <div class="nat-flag">🇯🇵</div>
                        <div class="nat-name">Nhật Bản</div>
                        <div class="nat-badge">Đã cập nhật</div>
                    </div>
                    <div class="nat-card unselected-pulse" data-val="Pháp">
                        <div class="nat-flag">🇫🇷</div>
                        <div class="nat-name">Pháp</div>
                    </div>
                    <div class="nat-card unselected-pulse" data-val="Nga">
                        <div class="nat-flag">🇷🇺</div>
                        <div class="nat-name">Nga</div>
                    </div>
                    <div class="nat-card unselected-pulse" data-val="Brazil">
                        <div class="nat-flag">🇧🇷</div>
                        <div class="nat-name">Brazil</div>
                    </div>
                </div>
            </div>
            <div class="form-group preset-section full-width">
                <label>Xuất Thân Có Sẵn <span style="font-weight:normal;opacity:0.5;">(Không bắt buộc, nhấn để điền tự động)</span></label>
                <div class="preset-hint" id="preset-hint">↑ Vui lòng chọn Quốc tịch trước</div>
                <div class="preset-drawer" id="preset-drawer"></div>
            </div>
            <div class="form-group full-width">
                <label for="c-appearance">Ngoại Hình</label>
                <textarea id="c-appearance" placeholder="Vóc dáng, khuôn mặt, sẹo, hình xăm, phong cách ăn mặc..."></textarea>
            </div>
            <div class="form-group full-width">
                <label for="c-personality">Tính Cách</label>
                <textarea id="c-personality" placeholder="Đặc điểm tính cách, cách hành xử, mâu thuẫn nội tâm..."></textarea>
            </div>
            <div class="form-group full-width">
                <label for="c-profession">Xuất Thân</label>
                <textarea id="c-profession" placeholder="Mô tả nghề nghiệp, kinh nghiệm, bối cảnh quá khứ..."></textarea>
            </div>

            <!-- ===== Mô hình Hành vi ===== -->
            <h3 class="divider-title">◈ Mô Hình Hành Vi</h3>

            <div class="form-group full-width">
                <label>Mô Hình Hành Vi Người Nhiễm <span style="font-weight:normal;opacity:0.5;">(Không thể đổi khi vào game)</span></label>
                <div class="behavior-selector" id="infected-behavior-selector">
                    <div class="behavior-card" data-val="Loại điên loạn">
                        <div class="recommend-badge">Gợi ý</div>
                        <div class="behavior-icon">💀</div>
                        <div class="behavior-name">Loại điên loạn</div>
                        <div class="behavior-desc">"Ồ? Là người sống sót à, hahaha..."</div>
                    </div>
                    <div class="behavior-card" data-val="Loại thông thường">
                        <div class="behavior-icon">🧟</div>
                        <div class="behavior-name">Loại thông thường</div>
                        <div class="behavior-desc">"Gràà oành..."</div>
                    </div>
                </div>
                <div class="behavior-hint" id="infected-behavior-hint">⚠ Vui lòng chọn Mô hình hành vi người nhiễm</div>
            </div>
            <div class="form-group full-width">
                <label>Mô Hình Hành Vi NPC <span style="font-weight:normal;opacity:0.5;">(Không thể đổi khi vào game)</span></label>
                <div class="behavior-selector" id="npc-behavior-selector">
                    <div class="behavior-card" data-val="Loại bình thường">
                        <div class="behavior-icon">🤝</div>
                        <div class="behavior-name">Loại bình thường</div>
                        <div class="behavior-desc">"Này, cậu cũng là người sống sót à? Đi chung đi."</div>
                    </div>
                    <div class="behavior-card" data-val="Loại toàn kẻ ác">
                        <div class="behavior-icon">🗡️</div>
                        <div class="behavior-name">Loại toàn kẻ ác</div>
                        <div class="behavior-desc">"Giao nhu yếu phẩm ra đây, không thì đừng trách tôi."</div>
                    </div>
                </div>
                <div class="behavior-hint" id="npc-behavior-hint">⚠ Vui lòng chọn Mô hình hành vi NPC</div>
            </div>

            <!-- ===== Chế độ Đặc điểm ===== -->
            <h3 class="divider-title">◈ Chế Độ Đặc Điểm</h3>

            <div class="mode-selector" id="mode-selector">
                <div class="mode-card" data-mode="god">
                    <div class="mode-name">⚡ Chế độ Sảng văn</div>
                    <div class="mode-desc">Điểm vô hạn, chọn thoải mái<br>Cho phép tạo Đặc điểm Tùy chỉnh</div>
                </div>
                <div class="mode-card" data-mode="normal">
                    <div class="mode-name">🎮 Chế độ Bình thường</div>
                    <div class="mode-desc">Khởi đầu với 8 điểm</div>
                </div>
                <div class="mode-card" data-mode="hard">
                    <div class="mode-name">💀 Chế độ Khó</div>
                    <div class="mode-desc">Khởi đầu với 5 điểm</div>
                </div>
            </div>

            <!-- ===== Đặc điểm Ngẫu nhiên ===== -->
            <div class="random-trait-bar" id="random-trait-bar">
                <button class="random-trait-btn" id="random-trait-btn" disabled>🎲 Chọn Ngẫu Nhiên</button>
                <span class="random-hint" id="random-hint">Cần chọn Chế độ để mở khóa</span>
            </div>

            <!-- ===== Hiển thị Điểm ===== -->
            <div class="points-bar" id="points-bar">
                <span class="points-label">Điểm Đặc Điểm Còn Lại</span>
                <span class="points-value positive" id="points-display">∞</span>
            </div>

            <div class="error-msg" id="points-error"></div>

            <!-- ===== Đặc điểm Đã chọn ===== -->
            <div class="selected-traits" id="selected-traits"></div>

            <!-- ===== Đặc điểm Tích cực ===== -->
            <div class="trait-section">
                <div class="trait-section-title"><span class="pos">▲ Đặc điểm Tích cực</span> (Tiêu tốn điểm)</div>
                <div class="tag-selector" id="positive-tags">
                    <span class="tag-option positive-trait" data-val="Chịu Rét" data-cost="1" data-special="E:1" data-desc="Chịu lạnh tốt hơn người thường, tốc độ giảm thân nhiệt trong môi trường lạnh chậm hơn đôi chút, giảm nguy cơ tê cóng nhẹ">Chịu Rét <span class="cost">1</span></span>
                    <span class="tag-option positive-trait" data-val="Mặt Mũi Hiền Lành" data-cost="1" data-special="C:1" data-desc="Trời sinh có khuôn mặt thân thiện, thiện cảm ban đầu của người lạ cao hơn một chút, khó bị coi là mối đe dọa">Mặt Mũi Hiền Lành <span class="cost">1</span></span>
                    <span class="tag-option positive-trait" data-val="Ăn Ít" data-cost="1" data-special="E:1" data-desc="Quen ăn với khẩu phần nhỏ, sức chịu đựng khi đói nhỉnh hơn, có thể tiết kiệm một chút khẩu phần lương thực">Ăn Ít <span class="cost">1</span></span>
                    <span class="tag-option positive-trait" data-val="Dậy Sớm" data-cost="1" data-special="E:1" data-desc="Trời sinh thói quen dậy sớm, hiệu suất hành động buổi sáng không bị suy giảm, thích hợp tuần tra sáng sớm">Dậy Sớm <span class="cost">1</span></span>
                    <span class="tag-option positive-trait" data-val="Quyền Anh Cơ Bản" data-cost="2" data-special="S:1,A:1" data-desc="Biết đấm và đỡ đòn cơ bản, khi tay không vẫn có khả năng phản kháng, nhưng gặp dân nhà nghề thì vẫn chịu thua">Quyền Anh Cơ Bản <span class="cost">2</span></span>
                    <span class="tag-option positive-trait" data-val="Cảm Giác Phương Hướng" data-cost="2" data-special="P:1,I:1" data-desc="Phương hướng bẩm sinh tốt, ít bị lạc đường nơi hoang dã, nhưng không đồng nghĩa với biết dùng la bàn hay đọc bản đồ">Cảm Giác Phương Hướng <span class="cost">2</span></span>
