    <script>
        // ===== Dữ liệu Đặc điểm (Kèm mô tả) =====
        const TRAIT_DATA = {};
        document.querySelectorAll('.tag-option[data-desc]').forEach(tag => {
            TRAIT_DATA[tag.dataset.val] = {
                cost: parseInt(tag.dataset.cost),
                desc: tag.dataset.desc,
                type: tag.classList.contains('positive-trait') ? 'positive' : 'negative'
            };
        });

        document.addEventListener('DOMContentLoaded', () => {
            // ===== Đồng bộ MVU thời gian thực =====
            let mvuReady = false;
            let syncTimer = null;

            async function initMvu() {
                try {
                    if (typeof waitGlobalInitialized === 'function') {
                        await waitGlobalInitialized('Mvu');
                        if (typeof Mvu !== 'undefined' && typeof getCurrentMessageId === 'function') {
                            mvuReady = true;
                            console.log('[Khởi tạo Nhân vật] Kết nối MVU thành công');
                        }
                    }
                } catch (e) {
                    console.warn('[Khởi tạo Nhân vật] Khởi tạo MVU thất bại:', e);
                }
            }

            async function syncToMvu(updates) {
                if (!mvuReady) return;
                try {
                    const msgId = getCurrentMessageId();
                    const data = Mvu.getMvuData({type: 'message', message_id: msgId});
                    if (!data || !data.stat_data) return;
                    for (const [path, value] of Object.entries(updates)) {
                        // Tawa đã trả lại cú pháp nguyên thủy cực kỳ an toàn của tác giả
                        _.set(data, path, value);
                    }
                    await Mvu.replaceMvuData(data, {type: 'message', message_id: msgId});
                    showSyncFeedback();
                } catch (e) {
                    console.warn('[Khởi tạo Nhân vật] Đồng bộ MVU thất bại:', e);
                }
            }

            function showSyncFeedback() {
                const indicator = document.getElementById('mvu-sync-indicator');
                if (!indicator) return;
                indicator.classList.add('visible');
                clearTimeout(syncTimer);
                syncTimer = setTimeout(() => indicator.classList.remove('visible'), 1200);
            }

            function buildSpecialMvuObj() {
                const mods = calcSpecialFromTraits();
                const obj = { S: 0, P: 0, E: 0, C: 0, I: 0, A: 0, L: 0 };
                SPECIAL_KEYS.forEach(k => {
                    obj[k] = Math.min(10, Math.max(-10, mods[k]));
                });
                return obj;
            }

            function syncTraitsAndSpecial() {
                if (!mvuReady) return;
                const updates = {};
                updates['stat_data.SPECIAL'] = buildSpecialMvuObj();
                // Đã fix lại ngoặc vuông cho biến có khoảng trắng và dấu tiếng Việt
                updates["stat_data['Đặc điểm']['Tích cực']"] = selectedPositive.map(t => t.name);
                updates["stat_data['Đặc điểm']['Tiêu cực']"] = selectedNegative.map(t => t.name);
                updates["stat_data['Đặc điểm']['Tùy chỉnh']"] = customTraits.map(t => t.name);
                syncToMvu(updates);
            }

            async function syncAllToMvu() {
                if (!mvuReady) return;
                try {
                    const msgId = getCurrentMessageId();
                    const data = Mvu.getMvuData({type: 'message', message_id: msgId});
                    if (!data || !data.stat_data) return;

                    // Giữ lại cách gọi mảng của Lodash (rất an toàn cho biến có khoảng trắng)
                    if (selectedNationality) {
                        _.set(data, ['stat_data', 'Trạng thái phái sinh', 'nationality'], selectedNationality);
                    }
                    _.set(data, ['stat_data', 'Giai đoạn thế giới'], selectedPhase);
                    _.set(data, ['stat_data', 'Mô hình hành vi người nhiễm'], selectedInfectedBehavior);
                    _.set(data, ['stat_data', 'Mô hình hành vi NPC'], selectedNpcBehavior);

                    const specialObj = buildSpecialMvuObj();
                    _.set(data, ['stat_data', 'SPECIAL'], specialObj);
                    _.set(data, ['stat_data', 'Đặc điểm', 'Tích cực'], selectedPositive.map(t => t.name));
                    _.set(data, ['stat_data', 'Đặc điểm', 'Tiêu cực'], selectedNegative.map(t => t.name));
                    _.set(data, ['stat_data', 'Đặc điểm', 'Tùy chỉnh'], customTraits.map(t => t.name));

                    const E = specialObj.E;
                    const L = specialObj.L;
                    const hpMax = 100 + E * 5;
                    const staminaMax = 100 + E * 5;
                    const moraleMax = 100 + L * 5;
                    _.set(data, ['stat_data', 'Trạng thái cốt lõi', 'hp_max'], Math.max(1, hpMax));
                    _.set(data, ['stat_data', 'Trạng thái cốt lõi', 'hp_current'], Math.max(1, hpMax));
                    _.set(data, ['stat_data', 'Trạng thái cốt lõi', 'stamina_max'], Math.max(1, staminaMax));
