            const SPECIAL_KEYS = ['S', 'P', 'E', 'C', 'I', 'A', 'L'];
            const SPECIAL_NAMES = { S: 'Sức Mạnh', P: 'Nhận Thức', E: 'Sức Bền', C: 'Sức Hút', I: 'Trí Tuệ', A: 'Nhanh Nhẹn', L: 'Ý Chí' };
