            function parseSpecialStr(str) {
                const result = {};
                SPECIAL_KEYS.forEach(k => result[k] = 0);
                if (!str) return result;
                str.split(',').forEach(pair => {
                    const [key, val] = pair.trim().split(':');
                    let actualKey = key.trim();
                    if (actualKey === 'W') actualKey = 'L';

                    if (actualKey && val && SPECIAL_KEYS.includes(actualKey)) {
                        result[actualKey] += parseInt(val.trim()) || 0;
                    }
                });
                return result;
            }

