                const name = el.dataset.val;
                const data = TRAIT_DATA[name];
                if (!data) return;

                clearTimeout(tooltipTimeout);

                const isPos = data.type === 'positive';
                const specialStr = el.dataset.special || '';
                let specialHtml = '';
                if (specialStr) {
                    const mods = parseSpecialStr(specialStr);
                    const parts = [];
                    SPECIAL_KEYS.forEach(k => {
                        if (mods[k] && mods[k] !== 0) {
                            const sign = mods[k] > 0 ? '+' : '';
                            const color = mods[k] > 0 ? '#22c55e' : '#ef4444';
                            parts.push(`<span style="color:${color};font-weight:700;">${SPECIAL_DISPLAY[k]}${sign}${mods[k]}</span>`);
                        }
                    });
                    if (parts.length > 0) {
                        specialHtml = `<div style="margin-top:6px; font-family:var(--font-mono); font-size:0.85em; letter-spacing:1px;">${parts.join(' ')}</div>`;
