            function getMutexTraits(traitName) {
                const conflicting = new Set();
                MUTEX_GROUPS.forEach(group => {
                    if (group.includes(traitName)) {
                        group.forEach(t => { if (t !== traitName) conflicting.add(t); });
                    }
                });
                return conflicting;
            }

            function handleMutex(traitName, isPositive) {
                const conflicting = getMutexTraits(traitName);
                if (conflicting.size === 0) return;

                conflicting.forEach(ct => {
                    const inPos = selectedPositive.find(t => t.name === ct);
                    const inNeg = selectedNegative.find(t => t.name === ct);
                    if (inPos) {
                        selectedPositive = selectedPositive.filter(t => t.name !== ct);
                        const tag = document.querySelector(`#positive-tags .tag-option[data-val="${ct}"]`);
                        if (tag) tag.classList.remove('selected');
                    }
                    if (inNeg) {
                        selectedNegative = selectedNegative.filter(t => t.name !== ct);
                        const tag = document.querySelector(`#negative-tags .tag-option[data-val="${ct}"]`);
                        if (tag) tag.classList.remove('selected');
                    }
                });
            }
            let currentMode = null;
            let selectedPositive = [];
            let selectedNegative = [];
            let customTraits = [];

            const modeCards = document.querySelectorAll('.mode-card');
            const pointsDisplay = document.getElementById('points-display');
            const pointsBar = document.getElementById('points-bar');
            const pointsError = document.getElementById('points-error');
            const confirmBtn = document.getElementById('confirm-btn');
            const customSection = document.getElementById('custom-trait-section');

