                card.addEventListener('click', () => {
                    modeCards.forEach(c => c.className = 'mode-card');
                    const mode = card.dataset.mode;
                    currentMode = mode;
                    card.classList.add(`selected-${mode}`);
                    customSection.classList.toggle('visible', mode === 'god');
                    pointsBar.style.display = mode === 'god' ? 'none' : 'flex';

                    selectedPositive.forEach(t => {
                        const tag = document.querySelector(`#positive-tags .tag-option[data-val="${t.name}"]`);
                        if (tag) tag.classList.remove('selected');
                    });
                    selectedNegative.forEach(t => {
                        const tag = document.querySelector(`#negative-tags .tag-option[data-val="${t.name}"]`);
                        if (tag) tag.classList.remove('selected');
                    });
                    selectedPositive = [];
                    selectedNegative = [];
                    customTraits = [];
                    renderCustomTraits();
                    updateSpecialOverview();

                    document.getElementById('custom-trait-name').value = '';
                    document.getElementById('custom-trait-desc').value = '';
                    SPECIAL_KEYS.forEach(k => {
                        const input = document.getElementById(`custom-special-${k}`);
                        if (input) input.value = 0;
                    });

                    const randBtn = document.getElementById('random-trait-btn');
                    const randHint = document.getElementById('random-hint');
                    randBtn.disabled = false;
                    randHint.textContent = mode === 'god' ? 'Chế độ Sảng văn: 100% tích cực' : mode === 'normal' ? 'Chế độ Bình thường: 40% tích cực' : 'Chế độ Khó: 20% tích cực';
                    recalcPoints();
                });
            });

            // ===== Randomize =====
            document.getElementById('random-trait-btn').addEventListener('click', () => {
                if (!currentMode) return;
                randomizeTraits();
            });

            function randomizeTraits() {
                selectedPositive.forEach(t => {
                    const tag = document.querySelector(`#positive-tags .tag-option[data-val="${t.name}"]`);
                    if (tag) tag.classList.remove('selected');
                });
                selectedNegative.forEach(t => {
                    const tag = document.querySelector(`#negative-tags .tag-option[data-val="${t.name}"]`);
                    if (tag) tag.classList.remove('selected');
                });
                selectedPositive = [];
                selectedNegative = [];
                customTraits = [];
                renderCustomTraits();

                const allPosTags = Array.from(document.querySelectorAll('#positive-tags .tag-option.positive-trait'));
                const allNegTags = Array.from(document.querySelectorAll('#negative-tags .tag-option.negative-trait'));

                const totalCount = Math.floor(Math.random() * 4) + 2; 
                let posRatio;
                if (currentMode === 'god') {
                    posRatio = 1;
                } else if (currentMode === 'normal') {
                    posRatio = 0.4 + (Math.random() * 0.2 - 0.1);
                } else {
                    posRatio = 0.2 + (Math.random() * 0.2 - 0.1);
                }

                const posCount = Math.round(totalCount * posRatio);
                const negCount = totalCount - posCount;

                const pickedPos = [];
                const pickedNeg = [];
                const pickedAll = new Set();

                function pickRandom(arr, count, picked) {
                    const pool = arr.filter(t => {
                        const name = t.dataset.val;
                        if (pickedAll.has(name)) return false;
                        const conflicting = getMutexTraits(name);
                        for (const c of conflicting) { if (pickedAll.has(c)) return false; }
                        return true;
                    });
                    const shuffled = pool.sort(() => Math.random() - 0.5);
                    for (const tag of shuffled) {
                        if (picked.length >= count) break;
                        const name = tag.dataset.val;
                        const conflicting = getMutexTraits(name);
                        let hasConflict = false;
                        for (const c of conflicting) { if (pickedAll.has(c)) { hasConflict = true; break; } }
                        if (hasConflict) continue;
                        picked.push(tag);
                        pickedAll.add(name);
                    }
                }

                if (posCount > 0) pickRandom(allPosTags, posCount, pickedPos);
                if (negCount > 0 && currentMode !== 'god') pickRandom(allNegTags, negCount, pickedNeg);

                pickedPos.forEach(tag => {
                    tag.classList.add('selected');
                    selectedPositive.push({ name: tag.dataset.val, cost: parseInt(tag.dataset.cost), isCustom: false });
                });
                pickedNeg.forEach(tag => {
                    tag.classList.add('selected');
                    selectedNegative.push({ name: tag.dataset.val, cost: parseInt(tag.dataset.cost), isCustom: false });
                });

                if (currentMode !== 'god') {
                    let safety = 20;
                    while (getAvailablePoints() !== Infinity && getUsedPoints() > getAvailablePoints() && selectedPositive.length > 0 && safety-- > 0) {
                        let maxIdx = 0, maxCost = 0;
                        selectedPositive.forEach((t, i) => { if (t.cost > maxCost) { maxCost = t.cost; maxIdx = i; } });
                        const removed = selectedPositive.splice(maxIdx, 1)[0];
                        pickedAll.delete(removed.name);
                        const tag = document.querySelector(`#positive-tags .tag-option[data-val="${removed.name}"]`);
                        if (tag) tag.classList.remove('selected');
                    }
                }

                const hintEl = document.getElementById('random-hint');
                const actualPos = selectedPositive.length;
                const actualNeg = selectedNegative.length;
                const modeText = currentMode === 'god' ? 'Sảng văn' : currentMode === 'normal' ? 'Bình thường' : 'Khó';
                hintEl.textContent = `Chế độ ${modeText}: ${actualPos} Tích cực - ${actualNeg} Tiêu cực (Tổng ${actualPos + actualNeg})`;

                recalcPoints();
            }

            document.querySelectorAll('.tag-option.positive-trait, .tag-option.negative-trait').forEach(t => t.classList.add('disabled'));

            function getAvailablePoints() {
                return currentMode ? MODE_POINTS[currentMode] : 0;
            }

            function getUsedPoints() {
                const posCost = selectedPositive.reduce((s, t) => s + t.cost, 0);
                const negCost = selectedNegative.reduce((s, t) => s + t.cost, 0);
                return posCost - negCost;
            }

            function recalcPoints() {
                if (!currentMode) {
                    pointsDisplay.textContent = 'Hãy chọn Chế độ';
                    pointsDisplay.className = 'points-value zero';
                    pointsError.textContent = '⚠ Vui lòng chọn Chế Độ Đặc Điểm trước';
                    confirmBtn.disabled = true;
                    document.querySelectorAll('.tag-option.positive-trait, .tag-option.negative-trait').forEach(t => t.classList.add('disabled'));
                    renderSelectedTraits();
                    updateSpecialOverview();
                    return;
                }

                const available = getAvailablePoints();
                const used = getUsedPoints();
                const remaining = available === Infinity ? Infinity : available - used;

                if (available === Infinity) {
                    pointsDisplay.textContent = '∞';
                    pointsDisplay.className = 'points-value positive';
                    pointsError.textContent = '';
                    confirmBtn.disabled = false;
                } else {
                    pointsDisplay.textContent = remaining;
                    if (remaining > 0) {
                        pointsDisplay.className = 'points-value positive';
                        pointsError.textContent = '';
                        confirmBtn.disabled = false;
                    } else if (remaining === 0) {
                        pointsDisplay.className = 'points-value zero';
                        pointsError.textContent = '';
                        confirmBtn.disabled = false;
                    } else {
                        pointsDisplay.className = 'points-value negative';
                        pointsError.textContent = `⚠ Vượt quá ${Math.abs(remaining)} điểm! Hãy bỏ bớt Đặc điểm Tích cực hoặc thêm Đặc điểm Tiêu cực.`;
                        confirmBtn.disabled = true;
                    }
                }

                updateTagStates(remaining);
                renderSelectedTraits();
                updateSpecialOverview();
                syncTraitsAndSpecial();
            }

            function updateTagStates(remaining) {
                if (getAvailablePoints() === Infinity) {
                    document.querySelectorAll('.tag-option.positive-trait, .tag-option.negative-trait').forEach(t => t.classList.remove('disabled'));
                    applyMutexDisabled();
                    return;
                }
                document.querySelectorAll('#positive-tags .tag-option.positive-trait').forEach(tag => {
                    const cost = parseInt(tag.dataset.cost);
                    const isSelected = tag.classList.contains('selected');
                    if (isSelected) {
                        tag.classList.remove('disabled');
                    } else {
                        tag.classList.toggle('disabled', cost > remaining);
                    }
                });
                document.querySelectorAll('#negative-tags .tag-option.negative-trait').forEach(t => t.classList.remove('disabled'));
                applyMutexDisabled();
            }

            function applyMutexDisabled() {
                const allSelected = [...selectedPositive, ...selectedNegative].map(t => t.name);
                document.querySelectorAll('.tag-option').forEach(tag => {
                    if (tag.classList.contains('selected')) return;
                    const name = tag.dataset.val;
                    const conflicting = getMutexTraits(name);
                    const hasConflict = allSelected.some(s => conflicting.has(s));
                    if (hasConflict) tag.classList.add('disabled');
                });
            }

            document.querySelectorAll('#positive-tags .tag-option').forEach(tag => {
                tag.addEventListener('click', () => {
                    if (!currentMode) return;
                    const name = tag.dataset.val;
                    const cost = parseInt(tag.dataset.cost);
                    if (tag.classList.contains('selected')) {
                        tag.classList.remove('selected');
                        selectedPositive = selectedPositive.filter(t => t.name !== name);
                    } else {
                        if (getAvailablePoints() !== Infinity) {
                            const remaining = getAvailablePoints() - getUsedPoints();
                            if (cost > remaining) return;
                        }
                        handleMutex(name, true);
                        tag.classList.add('selected');
                        selectedPositive.push({ name, cost, isCustom: false });
                    }
                    recalcPoints();
                });
            });

            document.querySelectorAll('#negative-tags .tag-option').forEach(tag => {
                tag.addEventListener('click', () => {
                    if (!currentMode) return;
                    const name = tag.dataset.val;
                    const cost = parseInt(tag.dataset.cost);
                    if (tag.classList.contains('selected')) {
                        tag.classList.remove('selected');
                        selectedNegative = selectedNegative.filter(t => t.name !== name);
                    } else {
                        handleMutex(name, false);
                        tag.classList.add('selected');
                        selectedNegative.push({ name, cost, isCustom: false });
                    }
                    recalcPoints();
                });
            });

            // ===== Đặc điểm Tùy chỉnh (Sảng văn) =====
            const customTraitHint = document.getElementById('custom-trait-hint');
            document.getElementById('add-custom-trait').addEventListener('click', () => {
                const nameInput = document.getElementById('custom-trait-name');
                const descInput = document.getElementById('custom-trait-desc');
                const name = nameInput.value.trim();
                const desc = descInput.value.trim();
                if (!name) {
                    nameInput.style.borderColor = 'var(--accent-red)';
                    nameInput.placeholder = 'Không được bỏ trống tên Đặc điểm!';
                    setTimeout(() => { nameInput.style.borderColor = 'var(--input-border)'; nameInput.placeholder = 'Tên Đặc điểm Tùy chỉnh'; }, 2000);
                    return;
                }
                if (customTraits.some(t => t.name === name)) {
                    nameInput.style.borderColor = 'var(--accent-red)';
                    nameInput.value = '';
                    nameInput.placeholder = 'Tên Đặc điểm đã tồn tại!';
                    setTimeout(() => { nameInput.style.borderColor = 'var(--input-border)'; nameInput.placeholder = 'Tên Đặc điểm Tùy chỉnh'; }, 2000);
                    return;
                }
                const special = {};
                SPECIAL_KEYS.forEach(k => {
                    const input = document.getElementById(`custom-special-${k}`);
                    const v = parseInt(input.value) || 0;
                    special[k] = Math.min(10, Math.max(-10, v));
                    input.value = special[k];
                });
                customTraits.push({ name, desc: desc || 'Đặc điểm tùy chỉnh', special });
                nameInput.value = '';
                descInput.value = '';
                SPECIAL_KEYS.forEach(k => {
                    document.getElementById(`custom-special-${k}`).value = 0;
                });
                renderCustomTraits();
                updateSpecialOverview();
                syncTraitsAndSpecial();

                customTraitHint.textContent = `✓ Đã thêm thành công 「${name}」`;
                customTraitHint.style.color = 'var(--accent-green)';
                setTimeout(() => {
                    customTraitHint.textContent = 'Viết Tên Đặc điểm và ấn Thêm, hệ thống cho phép sửa đổi các chỉ số S.P.E.C.I.A.L';
                    customTraitHint.style.color = 'var(--accent-yellow)';
                }, 2000);
            });

            function renderCustomTraits() {
                const list = document.getElementById('custom-traits-list');
                list.innerHTML = '';
                customTraits.forEach((t, idx) => {
                    const chip = document.createElement('span');
                    chip.className = 'custom-trait-chip';
                    let specialTags = '';
                    if (t.special) {
                        const parts = [];
                        SPECIAL_KEYS.forEach(k => {
                            if (t.special[k] && t.special[k] !== 0) {
                                const sign = t.special[k] > 0 ? '+' : '';
                                const cls = t.special[k] > 0 ? 'pos' : 'neg';
                                parts.push(`<span class="special-tag ${cls}">${SPECIAL_DISPLAY[k]}${sign}${t.special[k]}</span>`);
                            }
                        });
                        if (parts.length > 0) specialTags = ' ' + parts.join(' ');
                    }
                    chip.innerHTML = `✦ ${t.name}${specialTags} <span class="remove-x">✕</span>`;
                    chip.title = t.desc;
                    chip.addEventListener('click', () => {
                        customTraits.splice(idx, 1);
                        renderCustomTraits();
                        updateSpecialOverview();
                        syncTraitsAndSpecial();
                    });
                    list.appendChild(chip);
                });
            }

            function renderSelectedTraits() {
                const container = document.getElementById('selected-traits');
                container.innerHTML = '';

                selectedPositive.forEach(t => {
                    const chip = document.createElement('span');
                    chip.className = 'selected-trait-chip pos';
                    chip.innerHTML = `▲ ${t.name} <span class="cost">${t.cost}</span> <span class="remove-x">✕</span>`;
                    chip.addEventListener('click', () => {
                        selectedPositive = selectedPositive.filter(x => x !== t);
                        const presetTag = document.querySelector(`#positive-tags .tag-option[data-val="${t.name}"]`);
                        if (presetTag) presetTag.classList.remove('selected');
                        recalcPoints();
                    });
                    container.appendChild(chip);
                });

                selectedNegative.forEach(t => {
                    const chip = document.createElement('span');
                    chip.className = 'selected-trait-chip neg';
                    chip.innerHTML = `▼ ${t.name} <span class="cost">${t.cost}</span> <span class="remove-x">✕</span>`;
                    chip.addEventListener('click', () => {
                        selectedNegative = selectedNegative.filter(x => x !== t);
                        const presetTag = document.querySelector(`#negative-tags .tag-option[data-val="${t.name}"]`);
                        if (presetTag) presetTag.classList.remove('selected');
                        recalcPoints();
                    });
                    container.appendChild(chip);
                });
            }

            pointsBar.style.display = 'none';
            pointsDisplay.textContent = 'Hãy chọn Chế độ';
            pointsDisplay.className = 'points-value zero';
            confirmBtn.disabled = true;

            function calcSpecialFromTraits() {
                const total = {};
                SPECIAL_KEYS.forEach(k => total[k] = 0);

                [...selectedPositive, ...selectedNegative].forEach(t => {
                    const tag = document.querySelector(`.tag-option[data-val="${t.name}"]`);
                    const specialStr = tag ? tag.dataset.special : '';
                    const mods = parseSpecialStr(specialStr);
                    SPECIAL_KEYS.forEach(k => { total[k] += mods[k] || 0; });
                });

                customTraits.forEach(t => {
                    if (t.special) {
                        SPECIAL_KEYS.forEach(k => { total[k] += t.special[k] || 0; });
                    }
                });

                return total;
            }

            function updateSpecialOverview() {
                const mods = calcSpecialFromTraits();

                SPECIAL_KEYS.forEach(key => {
                    const val = mods[key];
                    const finalVal = Math.min(10, Math.max(-10, val));
                    const item = document.querySelector(`.special-item[data-attr="${key}"]`);
                    const valueEl = document.getElementById(`special-${key}`);
                    const deltaEl = document.getElementById(`special-${key}-delta`);
                    const barEl = document.getElementById(`special-${key}-bar`);

                    valueEl.textContent = finalVal;

                    if (finalVal > 0) {
                        const barWidth = (finalVal / 10) * 50; 
                        barEl.style.left = '50%';
                        barEl.style.width = `${barWidth}%`;
                    } else if (finalVal < 0) {
                        const barWidth = (Math.abs(finalVal) / 10) * 50; 
                        barEl.style.left = `${50 - barWidth}%`;
                        barEl.style.width = `${barWidth}%`;
                    } else {
                        barEl.style.left = '50%';
                        barEl.style.width = '0%';
                    }

                    if (val > 0) {
                        item.className = 'special-item boosted';
                        deltaEl.className = 'special-delta positive';
                        deltaEl.textContent = `+${val}`;
                    } else if (val < 0) {
                        item.className = 'special-item reduced';
                        deltaEl.className = 'special-delta negative';
                        deltaEl.textContent = `${val}`;
                    } else {
                        item.className = 'special-item neutral';
                        deltaEl.className = 'special-delta zero';
                        deltaEl.textContent = '±0';
                    }
                });
            }

            function showModal(title, msg) {
                const overlay = document.getElementById('builtin-modal');
                document.getElementById('modal-title').textContent = title;
                document.getElementById('modal-msg').innerHTML = msg;
                overlay.style.display = 'flex';
                document.getElementById('modal-btn').focus();
            }

            document.getElementById('modal-btn').addEventListener('click', () => {
                document.getElementById('builtin-modal').style.display = 'none';
            });

            document.getElementById('builtin-modal').addEventListener('click', (e) => {
                if (e.target === e.currentTarget) {
                    e.currentTarget.style.display = 'none';
                }
            });

            // ===== Xác nhận =====
            confirmBtn.addEventListener('click', async () => {
                const name = document.getElementById('c-name').value.trim();
                if (!name) {
                    showModal('Thiếu thông tin', 'Vui lòng điền <strong>Họ Tên</strong> trước khi vào!<br>Kẻ vô danh không bao giờ được nhớ đến trong thời mạt thế.');
                    return;
                }

                if (!selectedNationality) {
                    natCards.forEach(c => c.classList.add('unselected-pulse'));
                    natHint.style.display = 'inline';
                    const natSelector = document.getElementById('nationality-selector');
                    natSelector.scrollIntoView({ behavior: 'smooth', block: 'center' });
                    showModal('Thiếu thông tin', 'Vui lòng chọn <strong>Quốc Tịch</strong> trước khi vào!<br>Quốc tịch quyết định điểm khởi đầu và môi trường của bạn.');
                    return;
                }

                if (!selectedInfectedBehavior) {
                    document.getElementById('infected-behavior-hint').style.display = 'block';
                    document.getElementById('infected-behavior-selector').scrollIntoView({ behavior: 'smooth', block: 'center' });
                    showModal('Thiếu thông tin', 'Vui lòng chọn <strong>Mô Hình Hành Vi Người Nhiễm</strong> trước khi vào!<br>Mô hình này cho biết bọn chúng nguy hiểm đến mức nào.');
                    return;
                }

                if (!selectedNpcBehavior) {
                    document.getElementById('npc-behavior-hint').style.display = 'block';
                    document.getElementById('npc-behavior-selector').scrollIntoView({ behavior: 'smooth', block: 'center' });
                    showModal('Thiếu thông tin', 'Vui lòng chọn <strong>Mô Hình Hành Vi NPC</strong> trước khi vào!<br>Mô hình này quyết định bạn có nên tin tưởng người sống sót khác hay không.');
                    return;
                }

                const ctNameInput = document.getElementById('custom-trait-name');
                const ctDescInput = document.getElementById('custom-trait-desc');
                const ctName = ctNameInput.value.trim();
                const ctDesc = ctDescInput.value.trim();
                if (ctName || ctDesc) {
                    const customSection = document.getElementById('custom-trait-section');
                    customSection.scrollIntoView({ behavior: 'smooth', block: 'center' });
                    if (ctName) ctNameInput.style.borderColor = 'var(--accent-yellow)';
                    if (ctDesc) ctDescInput.style.borderColor = 'var(--accent-yellow)';
                    showModal('Đặc điểm bị bỏ qua', 'Có Đặc điểm Tùy chỉnh đã viết xong nhưng <strong>Chưa ấn Thêm</strong>!<br>Vui lòng ấn "＋ Thêm" vào danh sách hoặc làm trống ô nhập.');
                    setTimeout(() => {
                        ctNameInput.style.borderColor = 'var(--input-border)';
                        ctDescInput.style.borderColor = 'var(--input-border)';
                    }, 3000);
                    return;
                }

                if (getAvailablePoints() !== Infinity) {
                    const remaining = getAvailablePoints() - getUsedPoints();
                    if (remaining < 0) return;
                }

                /* Đồng bộ toàn bộ MVU lần cuối */
                await syncAllToMvu();

                const gender = document.getElementById('c-gender').value.trim() || 'Không rõ';
                const age = document.getElementById('c-age').value.trim() || 'Không rõ';
                const nationality = selectedNationality;
                const appearance = document.getElementById('c-appearance').value.trim();
                const personality = document.getElementById('c-personality').value.trim();
                const profession = document.getElementById('c-profession').value.trim();

                const posTraits = selectedPositive.map(t => t.name);
                const negTraits = selectedNegative.map(t => t.name);

                const modeLabel = currentMode === 'god' ? 'Sảng văn' : currentMode === 'normal' ? 'Bình thường' : currentMode === 'hard' ? 'Khó' : 'Chưa chọn';

                // Chuỗi S.P.E.C.I.A.L.
                const specialMods = calcSpecialFromTraits();
                const specialLines = SPECIAL_KEYS.map(key => {
                    const mod = specialMods[key];
                    const rawVal = mod;
                    const finalVal = Math.min(10, Math.max(-10, rawVal));
                    const capped = finalVal !== rawVal ? ` [Đã giới hạn]` : '';
                    const modStr = mod >= 0 ? `+${mod}` : `${mod}`;
                    return `S.P.E.C.I.A.L. ${SPECIAL_NAMES[key]}(${SPECIAL_DISPLAY[key]}): ${finalVal} (${modStr})${capped}`;
                }).join('\n');

                const posDetail = selectedPositive.map(t => {
                    const data = TRAIT_DATA[t.name];
                    return `${t.name} (${data ? data.desc : ''})`;
                }).join('、');

                const negDetail = selectedNegative.map(t => {
                    const data = TRAIT_DATA[t.name];
                    return `${t.name} (${data ? data.desc : ''})`;
                }).join('、');

                const customDetail = customTraits.map(t => {
                    let detail = `${t.name}${t.desc ? ' (' + t.desc + ')' : ''}`;
                    if (t.special) {
                        const parts = [];
                        SPECIAL_KEYS.forEach(k => {
                            if (t.special[k] && t.special[k] !== 0) {
                                const sign = t.special[k] > 0 ? '+' : '';
                                parts.push(`${SPECIAL_NAMES[k]}(${SPECIAL_DISPLAY[k]})${sign}${t.special[k]}`);
                            }
                        });
                        if (parts.length > 0) detail += ` [${parts.join(', ')}]`;
                    }
                    return detail;
                }).join('、');

                const sysMessage = `/sys [Hồ Sơ Người Sống Sót - Chế độ ${modeLabel}]
**Họ Tên**: ${name}
**Giới Tính**: ${gender}
**Tuổi**: ${age}
**Giai Đoạn**: ${selectedPhase}
**Quốc Tịch**: ${nationality}
**Ngoại Hình**: ${appearance || 'Chưa định hình'}
**Tính Cách**: ${personality || 'Chưa định hình'}
**Xuất Thân**: ${profession || 'Chưa định hình'}
**Chế Độ Đặc Điểm**: ${modeLabel}
**Mô Hình Hành Vi Người Nhiễm**: ${selectedInfectedBehavior}
**Mô Hình Hành Vi NPC**: ${selectedNpcBehavior}
**Chỉ Số Cơ Bản S.P.E.C.I.A.L.**:
${specialLines}${posTraits.length > 0 ? '\n**Đặc Điểm Tích Cực**: ' + posDetail : ''}${negTraits.length > 0 ? '\n**Đặc Điểm Tiêu Cực**: ' + negDetail : ''}${customTraits.length > 0 ? '\n**Đặc Điểm Tùy Chỉnh**: ' + customDetail : ''}
<prompt>Dựa vào các thông số trên, hãy sắp xếp hoàn cảnh xuất hiện, mạch truyện và xây dựng NPC xoay quanh nhân vật chính một cách logic và hấp dẫn.</prompt>`;

                const fullMessage = `${sysMessage} | /trigger`;

                document.body.innerHTML = '<div style="display:flex; justify-content:center; align-items:center; height:100vh; background:#0a0a0a;"><h1 style="font-family:monospace; color:#ef4444; text-shadow:0 0 10px rgba(239,68,68,0.5); letter-spacing:3px;">☠️ Đã niêm phong hồ sơ...</h1></div>';

                localStorage.removeItem('char-appearance');
                localStorage.removeItem('char-personality');
                localStorage.removeItem('char-profession');

                if (typeof triggerSlash === 'function' && typeof getCurrentMessageId === 'function') {
                    triggerSlash(fullMessage);
                    const currentMessageId = getCurrentMessageId();
                    setTimeout(() => { triggerSlash(`/cut ${currentMessageId}`); }, 1500);
                } else {
                    console.log("Câu lệnh xuất ra:", fullMessage);
                    alert("Đã khóa hồ sơ nhân vật! Đưa vào môi trường SillyTavern để tiến hành tự động gửi lệnh.");
                }
            });

            // ===== Toggle Theme =====
            const themeToggle = document.getElementById('theme-toggle');
            const savedTheme = localStorage.getItem('char-theme');
            if (savedTheme === 'light') {
                document.body.classList.add('light-mode');
                themeToggle.textContent = '☀️';
            }

            let isDragging = false;
            let dragStartX = 0, dragStartY = 0;
            let btnStartX = 0, btnStartY = 0;
            let hasMoved = false;

            function getBtnPos() {
                const r = themeToggle.getBoundingClientRect();
                return { x: r.left, y: r.top };
            }

            themeToggle.addEventListener('pointerdown', (e) => {
                isDragging = true;
                hasMoved = false;
                const pos = getBtnPos();
                dragStartX = e.clientX;
                dragStartY = e.clientY;
                btnStartX = pos.x;
                btnStartY = pos.y;
                themeToggle.classList.add('dragging');
                themeToggle.setPointerCapture(e.pointerId);
                e.preventDefault();
            });

            themeToggle.addEventListener('pointermove', (e) => {
                if (!isDragging) return;
                const dx = e.clientX - dragStartX;
                const dy = e.clientY - dragStartY;
                if (Math.abs(dx) > 3 || Math.abs(dy) > 3) hasMoved = true;
                let newX = btnStartX + dx;
                let newY = btnStartY + dy;
                newX = Math.max(0, Math.min(window.innerWidth - 48, newX));
                newY = Math.max(0, Math.min(window.innerHeight - 48, newY));
                themeToggle.style.left = newX + 'px';
                themeToggle.style.top = newY + 'px';
                themeToggle.style.right = 'auto';
            });

            themeToggle.addEventListener('pointerup', (e) => {
                if (!isDragging) return;
                isDragging = false;
                themeToggle.classList.remove('dragging');
                if (!hasMoved) {
                    document.body.classList.toggle('light-mode');
                    const isLight = document.body.classList.contains('light-mode');
                    themeToggle.textContent = isLight ? '☀️' : '🌙';
                    localStorage.setItem('char-theme', isLight ? 'light' : 'dark');
                }
            });

            themeToggle.addEventListener('click', (e) => {
                e.preventDefault();
            });

            function clampToggleButton() {
                const btnW = themeToggle.offsetWidth;
                const btnH = themeToggle.offsetHeight;
                const maxX = window.innerWidth - btnW;
                const maxY = window.innerHeight - btnH;
                let curX = themeToggle.offsetLeft;
                let curY = themeToggle.offsetTop;
                if (themeToggle.style.left === '') {
                    const rect = themeToggle.getBoundingClientRect();
                    curX = rect.left;
                    curY = rect.top;
                }
                const clampedX = Math.max(0, Math.min(maxX, curX));
                const clampedY = Math.max(0, Math.min(maxY, curY));
                themeToggle.style.left = clampedX + 'px';
                themeToggle.style.top = clampedY + 'px';
                themeToggle.style.right = 'auto';
            }

            window.addEventListener('resize', clampToggleButton);
            clampToggleButton();
        });
    </script>
</body>
</html>
