<script type="module">
    // ===== Chuyển đổi Tab =====
    const tabBtns = document.querySelectorAll('.tab-btn');
    const tabContents = document.querySelectorAll('.tab-content');

    // ===== Chuyển đổi Giao diện =====
    const styleSwitch = document.getElementById('styleSwitch');
    const savedTheme = localStorage.getItem('statusbar_theme');
    if (savedTheme === 'light') {
        document.body.classList.add('theme-light');
        styleSwitch.classList.add('active');
    }
    styleSwitch.addEventListener('click', () => {
        styleSwitch.classList.toggle('active');
        document.body.classList.toggle('theme-light');
        const isLight = document.body.classList.contains('theme-light');
        localStorage.setItem('statusbar_theme', isLight ? 'light' : 'dark');
    });

    // Chuyển đổi phân khu Kiến trúc
    window.switchBuildingZone = function(bldgId, zone) {
        const card = document.querySelector(`[data-zone="${bldgId}_${zone}"]`);
        if (!card) return;
        const parent = card.closest('.building-sections');
        const bar = card.closest('.building-card').querySelector('.building-zone-bar');
        parent.querySelectorAll('.building-section').forEach(s => s.classList.remove('active'));
        bar.querySelectorAll('.building-zone-tab').forEach(t => t.classList.remove('active'));
        card.classList.add('active');
        bar.querySelector(`.building-zone-tab.${zone}`).classList.add('active');
    };

    tabBtns.forEach(btn => {
        btn.addEventListener('click', () => {
            tabBtns.forEach(b => b.classList.remove('active'));
            tabContents.forEach(c => c.classList.remove('active'));
            btn.classList.add('active');
            const tabId = btn.getAttribute('data-tab');
            const target = document.getElementById(tabId);
            if (target) {
                target.classList.add('active');
            }
        });
    });

    // ===== Đồng hồ thời gian thực =====
    const clockEl = document.getElementById('clock');
    function updateClock() {
        const now = new Date();
        clockEl.textContent = now.toLocaleTimeString('vi-VN', { hour12: false });
    }
    updateClock();
    setInterval(updateClock, 1000);

    // ===== Lấy dữ liệu biến từ MVU và Render =====
    function renderUI(statData) {
        const get = (path, fallback) => _.get(statData, path, fallback ?? '');

        /* Render an toàn: Một module bị lỗi không ảnh hưởng các phần khác */
        const safe = (label, fn) => { try { fn(); } catch(e) { console.error('[Thanh trạng thái] Lỗi hiển thị:', label, e); } };

        /* ===== Hàm tiện ích dùng chung (Kho chứa + Hành trang) ===== */
        function extractEmoji(detail) {
            const m = (detail || '').match(/^(\p{Emoji_Presentation}|\p{Extended_Pictographic})/u);
            return m ? m[1] : '📦';
        }
        function stripEmoji(detail) {
            return (detail || '').replace(/^(\p{Emoji_Presentation}|\p{Extended_Pictographic})\s*/u, '');
        }
        function getRarity(detail) {
            const d = (detail || '').toLowerCase();
            if (d.includes('huyền thoại') || d.includes('legendary')) return 'legendary';
            if (d.includes('sử thi') || d.includes('epic')) return 'epic';
            if (d.includes('hiếm') || d.includes('rare')) return 'rare';
            if (d.includes('xuất sắc') || d.includes('uncommon') || d.includes('tốt')) return 'uncommon';
            return 'common';
        }
        const rarityLabels = {
            common: 'COMMON', uncommon: 'UNCOMMON', rare: 'RARE', epic: 'EPIC', legendary: 'LEGEND'
        };
        function parseCount(detail) {
            const d = detail || '';
            let m = d.match(/[×xX]\s*(\d+)/);
            if (m) return parseInt(m[1]);
            m = d.match(/\b(\d+)\s*(cái|chiếc|bình|hộp|bộ|nhánh|khẩu|viên|phần)?\b/i);
            if (m) return parseInt(m[1]);
            m = d.match(/Số lượng[:：]\s*(\d+)/i);
            if (m) return parseInt(m[1]);
            return 0;
        }
        function cleanDetail(detail) {
            return stripEmoji(detail)
                .replace(/[×xX]\s*\d+/, '')
                .replace(/\b\d+\s*(cái|chiếc|bình|hộp|bộ|nhánh|khẩu|viên|phần)?\b/i, '')
                .replace(/Số lượng[:：]\s*\d+/i, '')
                .replace(/^[,，、\s]+/, '')
                .trim();
        }
        function renderStorageItems(storageData, buildingName) {
            if (!storageData || typeof storageData !== 'object') {
                return `<div class="building-section-content">${storageData || 'Trống'}</div>`;
            }
            const entries = Array.isArray(storageData)
                ? storageData.map((v, i) => [v.name || `Vật phẩm ${i+1}`, v])
                : Object.entries(storageData);
            if (entries.length === 0) {
                return '<div class="building-section-content" style="color:var(--text-secondary);">Kho chứa trống</div>';
            }
            let totalW = 0;
            const items = entries.map(([itemName, itemData]) => {
                const detail = (itemData && itemData.detail) || '';
                const weight = parseFloat(itemData && itemData.weight) || 0;
                totalW += weight;
                const icon = extractEmoji(detail);
                const rarity = getRarity(detail);
                const count = parseCount(detail);
                const cleanDesc = cleanDetail(detail);
                const countHtml = count > 1 ? `<span class="bag-item-count">×${count}</span>` : '';
                const rarityTag = rarity !== 'common'
                    ? `<span class="bag-item-rarity-tag rarity-tag-${rarity}">${rarityLabels[rarity]}</span>`
                    : '';
                const safeName = itemName.replace(/"/g, '&quot;');
                const safeBName = buildingName.replace(/"/g, '&quot;');
                return `<li class="bag-item storage-item rarity-${rarity}" data-item="${safeName}" data-building="${safeBName}">
                    <span class="rarity-bar rarity-${rarity}"></span>
                    <button class="storage-item-retrieve" title="Lấy ra hành trang" data-item="${safeName}" data-building="${safeBName}">📤</button>
                    <button class="bag-item-discard" title="Vứt bỏ" data-item="${safeName}" data-building="${safeBName}">✕</button>
                    <div class="bag-item-header">
                        <div class="bag-item-icon-box">${icon}</div>
                        <div class="bag-item-title">
                            <span class="bag-item-name">${itemName}</span>
                            ${countHtml}
                        </div>
                    </div>
                    ${cleanDesc ? `<div class="bag-item-detail">${cleanDesc}</div>` : ''}
                    <div class="bag-item-footer">
                        ${weight ? `<span class="bag-item-weight">${weight}kg</span>` : '<span></span>'}
                        ${rarityTag}
                    </div>
                </li>`;
            }).join('');
            return `<ul class="storage-grid">${items}</ul>
                <div class="bag-total" style="margin-top:10px;">
                    <span>Kho chứa ${entries.length} Món</span><span class="total-val">${totalW.toFixed(1)} kg</span>
                </div>`;
        }

        // ===== Avatar Header & Tên Người Dùng =====
        try {
            const avatarUrl = window.parent.document.querySelector('#user_avatar_image')?.src;
            const userAvatarElement = document.querySelector('.user_avatar');
            if (userAvatarElement && avatarUrl) {
                userAvatarElement.style.backgroundImage = `url('${avatarUrl}')`;
            }
        } catch(e) {}
        try {
            const userName = window.parent.SillyTavern?.getContext()?.name1 || '';
            if (userName) {
                document.getElementById('profileName').textContent = userName;
                // Tạo số seri giả lập từ tên
                let hash = 0;
                for (let i = 0; i < userName.length; i++) hash = ((hash << 5) - hash + userName.charCodeAt(i)) | 0;
                const serial = Math.abs(hash).toString(16).toUpperCase().slice(0, 6).padEnd(6, '0');
                document.getElementById('profileSerial').textContent = 'NO.' + serial;
            }
        } catch(e) {}

        // ===== Hàm hỗ trợ render SPECIAL Mini =====
        function renderMiniSpecial(sp) {
            if (!sp || typeof sp !== 'object') return '';
            const keys = ['S','P','E','C','I','A','L'];
