                            <div class="special-h-value">${sign}${val}</div>
                        </div>`;
                    }).join('')}
                </div>`;

        } else {
            specialBlock.innerHTML = '';
        }

        // ===== 1. Hiển thị Đặc điểm =====
        const traitData = get('Đặc điểm', {});
