        // ===== 2.5 Hệ thống Kiến trúc =====
        safe('Kiến trúc', () => {
        const buildingCard = document.getElementById('buildingCard');
        const buildings = get('Kiến trúc', {});
        const buildingEntries = Object.entries(buildings);
        const statusMap = { 'Nguyên vẹn': 'intact', 'Hư hỏng nhẹ': 'minor', 'Hư hỏng vừa': 'moderate', 'Hư hỏng nặng': 'severe', 'Phá hủy': 'destroyed', 'Đang xây dựng': 'building' };
        const conditionColor = (c) => c > 80 ? '#22c55e' : c > 60 ? '#eab308' : c > 40 ? '#f97316' : c > 20 ? '#ef4444' : '#dc2626';

        // Tạo SVG ngôi nhà dựa vào tình trạng (condition)
        function houseSvg(cond) {
