    // ===== Vứt bỏ vật phẩm → Đồng bộ MVU thời gian thực =====
    async function discardItem(itemName, liElement) {
        try {
            const lastMsgId = getLastMessageId();
            const messages = getChatMessages('0-' + lastMsgId, { role: 'assistant' });
            if (!messages || messages.length === 0) return;
            const targetMsgId = messages[messages.length - 1].message_id;

            if (window.Mvu && typeof Mvu.replaceMvuData === 'function') {
                const fullData = Mvu.getMvuData({ type: 'message', message_id: targetMsgId });
                if (fullData && fullData.stat_data) {
                    if (!fullData.stat_data['Vật phẩm'] || !(itemName in fullData.stat_data['Vật phẩm'])) {
                        console.warn('[Thanh trạng thái] Vứt bỏ thất bại: Vật phẩm không tồn tại', itemName);
                        if (liElement) liElement.classList.remove('discarding');
                        return;
                    }
                    delete fullData.stat_data['Vật phẩm'][itemName];
                    await Mvu.replaceMvuData(fullData, { type: 'message', message_id: targetMsgId });

                    const newStatData = await getLatestStatData();
                    if (newStatData && Object.keys(newStatData).length > 0) {
                        renderUI(newStatData);
                    }
                }
            }
            console.log('[Thanh trạng thái] Đã vứt bỏ:', itemName);
        } catch (err) {
            console.error('[Thanh trạng thái] Lỗi vứt bỏ vật phẩm:', err);
            if (liElement) liElement.classList.remove('discarding');
        }
    }

    // ===== Vứt bỏ vật phẩm kho chứa → Đồng bộ MVU thời gian thực =====
    async function discardStorageItem(itemName, buildingName, liElement) {
        try {
            const lastMsgId = getLastMessageId();
            const messages = getChatMessages('0-' + lastMsgId, { role: 'assistant' });
            if (!messages || messages.length === 0) return;
            const targetMsgId = messages[messages.length - 1].message_id;

            if (window.Mvu && typeof Mvu.replaceMvuData === 'function') {
                const fullData = Mvu.getMvuData({ type: 'message', message_id: targetMsgId });
                if (fullData && fullData.stat_data) {
                    const sd = fullData.stat_data;
                    if (!sd['Kiến trúc'] || !sd['Kiến trúc'][buildingName] ||
                        !sd['Kiến trúc'][buildingName].storage || !(itemName in sd['Kiến trúc'][buildingName].storage)) {
                        console.warn('[Thanh trạng thái] Lỗi vứt bỏ vật phẩm kho: Không tồn tại', itemName);
                        if (liElement) liElement.classList.remove('discarding');
                        return;
                    }
                    delete sd['Kiến trúc'][buildingName].storage[itemName];
                    await Mvu.replaceMvuData(fullData, { type: 'message', message_id: targetMsgId });

                    const newStatData = await getLatestStatData();
                    if (newStatData && Object.keys(newStatData).length > 0) {
                        renderUI(newStatData);
                    }
                }
            }
            console.log('[Thanh trạng thái] Đã vứt bỏ khỏi kho:', itemName, '←', buildingName);
        } catch (err) {
            console.error('[Thanh trạng thái] Lỗi vứt bỏ vật phẩm kho:', err);
            if (liElement) liElement.classList.remove('discarding');
        }
    }

    // ===== Cất vào Nơi trú ẩn → Đồng bộ MVU thời gian thực =====
    async function storeToStorage(itemName, buildingName, liElement) {
        try {
            const lastMsgId = getLastMessageId();
            const messages = getChatMessages('0-' + lastMsgId, { role: 'assistant' });
            if (!messages || messages.length === 0) return;
            const targetMsgId = messages[messages.length - 1].message_id;

            if (window.Mvu && typeof Mvu.replaceMvuData === 'function') {
                const fullData = Mvu.getMvuData({ type: 'message', message_id: targetMsgId });
                if (fullData && fullData.stat_data) {
                    const sd = fullData.stat_data;
                    if (!sd['Vật phẩm'] || !(itemName in sd['Vật phẩm'])) {
                        console.warn('[Thanh trạng thái] Cất thất bại: Không có vật phẩm', itemName);
                        if (liElement) liElement.classList.remove('discarding');
                        return;
                    }
                    const itemData = sd['Vật phẩm'][itemName];
                    delete sd['Vật phẩm'][itemName];
                    if (!sd['Kiến trúc']) sd['Kiến trúc'] = {};
                    if (!sd['Kiến trúc'][buildingName]) sd['Kiến trúc'][buildingName] = {};
                    if (!sd['Kiến trúc'][buildingName].storage || typeof sd['Kiến trúc'][buildingName].storage !== 'object') {
                        sd['Kiến trúc'][buildingName].storage = {};
                    }
                    sd['Kiến trúc'][buildingName].storage[itemName] = itemData;
                    await Mvu.replaceMvuData(fullData, { type: 'message', message_id: targetMsgId });

                    // Chủ động làm mới toàn bộ UI
                    const newStatData = await getLatestStatData();
                    if (newStatData && Object.keys(newStatData).length > 0) {
                        renderUI(newStatData);
                    }
                }
            }

            console.log('[Thanh trạng thái] Đã cất vào Nơi trú ẩn:', itemName, '→', buildingName);
        } catch (err) {
            console.error('[Thanh trạng thái] Cất vào nơi trú ẩn thất bại:', err);
            if (liElement) liElement.classList.remove('discarding');
        }
    }

    // ===== Lấy từ Nơi trú ẩn → Đồng bộ MVU thời gian thực =====
    async function retrieveFromStorage(itemName, buildingName, liElement) {
        try {
            const lastMsgId = getLastMessageId();
            const messages = getChatMessages('0-' + lastMsgId, { role: 'assistant' });
            if (!messages || messages.length === 0) return;
            const targetMsgId = messages[messages.length - 1].message_id;

            if (window.Mvu && typeof Mvu.replaceMvuData === 'function') {
                const fullData = Mvu.getMvuData({ type: 'message', message_id: targetMsgId });
                if (fullData && fullData.stat_data) {
                    const sd = fullData.stat_data;
                    if (!sd['Kiến trúc'] || !sd['Kiến trúc'][buildingName] ||
                        !sd['Kiến trúc'][buildingName].storage || !(itemName in sd['Kiến trúc'][buildingName].storage)) {
                        console.warn('[Thanh trạng thái] Lấy ra thất bại: Vật phẩm trong kho không tồn tại', itemName);
                        if (liElement) liElement.classList.remove('retrieving');
                        return;
                    }
                    const itemData = sd['Kiến trúc'][buildingName].storage[itemName];
                    delete sd['Kiến trúc'][buildingName].storage[itemName];
                    if (!sd['Vật phẩm']) sd['Vật phẩm'] = {};
                    sd['Vật phẩm'][itemName] = itemData;
                    await Mvu.replaceMvuData(fullData, { type: 'message', message_id: targetMsgId });

                    // Chủ động làm mới toàn bộ UI
                    const newStatData = await getLatestStatData();
                    if (newStatData && Object.keys(newStatData).length > 0) {
                        renderUI(newStatData);
                    }
                }
            }

            console.log('[Thanh trạng thái] Đã lấy từ Nơi trú ẩn:', itemName, '←', buildingName);
        } catch (err) {
            console.error('[Thanh trạng thái] Lấy từ nơi trú ẩn thất bại:', err);
            if (liElement) liElement.classList.remove('retrieving');
        }
    }

    // ===== Lấy dữ liệu biến của lượt AI mới nhất =====
    async function getLatestStatData() {
        try {
            const lastMsgId = getLastMessageId();
            // Truy ngược từ lượt mới nhất để tìm tin nhắn AI cuối cùng
            const messages = getChatMessages('0-' + lastMsgId, { role: 'assistant' });
            if (!messages || messages.length === 0) {
                return null;
            }
            const targetMsgId = messages[messages.length - 1].message_id;

            // Ưu tiên sử dụng MVU framework để lấy dữ liệu
            let mvuData = null;
            if (window.Mvu && typeof Mvu.getMvuData === 'function') {
                mvuData = Mvu.getMvuData({ type: 'message', message_id: targetMsgId });
            }
            // Hạ cấp xuống việc truy xuất biến nội bộ nếu cần
            if (!mvuData || Object.keys(_.get(mvuData, 'stat_data', {})).length === 0) {
                mvuData = getVariables({ type: 'message', message_id: targetMsgId });
            }
            const statData = _.get(mvuData, 'stat_data', null);
            if (!statData || Object.keys(statData).length === 0) {
                console.warn('[Thanh trạng thái] Dữ liệu biến trống, thử tìm lùi lại');
                /* Fallback: Tìm lùi từ tin nhắn AI mới nhất, chọn tầng có dữ liệu */
                for (let i = messages.length - 1; i >= Math.max(0, messages.length - 10); i--) {
                    const fallbackId = messages[i].message_id;
                    let fallbackData = null;
                    if (window.Mvu && typeof Mvu.getMvuData === 'function') {
                        fallbackData = Mvu.getMvuData({ type: 'message', message_id: fallbackId });
                    }
                    if (fallbackData && Object.keys(_.get(fallbackData, 'stat_data', {})).length > 0) {
                        return _.get(fallbackData, 'stat_data', null);
                    }
                }
            }
            return statData;
        } catch (err) {
            console.error('[Thanh trạng thái] Lỗi getLatestStatData:', err);
            return null;
        }
    }

    // ===== Khởi tạo: Lấy dữ liệu biến từ MVU =====
    async function init() {
        try {
            await waitGlobalInitialized('Mvu');

            // Nhận biến MVU từ lượt AI mới nhất
            const statData = await getLatestStatData();

            if (statData && Object.keys(statData).length > 0) {
                renderUI(statData);
            }

            // Lắng nghe sự kiện cập nhật biến, làm mới UI thời gian thực
            eventOn(Mvu.events.VARIABLE_UPDATE_ENDED, async () => {
                try {
                    const newStatData = await getLatestStatData();
                    if (newStatData && Object.keys(newStatData).length > 0) {
                        renderUI(newStatData);
                    }
                } catch (e) {
                    console.error('[Thanh trạng thái] Callbacks cập nhật biến thất bại:', e);
                }
            });
        } catch (err) {
            console.error('[Thanh trạng thái] Khởi tạo thất bại:', err);
        }
    }

    $(errorCatched(init));
</script>
</body>
