// AI thường viết đối tượng z.record dưới dạng chuỗi JSON (như "storage": "{}" hoặc "storage": "{...}"),
// Hàm này tự động phân tích chuỗi thành đối tượng, tránh lỗi xác thực ZOD khiến toàn bộ lệnh insert/replace bị từ chối
const parseStr = (schema) => z.preprocess((val) => {
  if (typeof val === 'string') {
    try { return JSON.parse(val); } catch (e) { console.warn('[ZOD] Lỗi phân tích chuỗi JSON:', val); return val; }
  }
  return val;
}, schema);

