                const idx = parseInt(btn.dataset.delLog);
                deleteFishLog(idx);
            });
        });
        p.document.querySelectorAll('[data-reset-record]').forEach(btn => {
            btn.addEventListener('click', (e) => {
                e.stopPropagation();
                const type = btn.dataset.resetRecord;
                resetFishRecord(type);
            });
        });
