{{!-- Bộ điều khiển động thai sản và sinh lý --}}
<%_
var _needBaseCycle = true;
var _needPeriodItems = false;
var _needOvulationItems = false;

var _isPregnant = false;
var _isLatePregnancy = false; // Thai kỳ cuối, cần tải trước sinh nở
var _isLabor = false; // Đang sinh nở
var _isPostpartum = false; // Phục hồi sau sinh
var _isNursing = false; // Cho con bú

var _allPhys = [];
_allPhys.push(getvar('stat_data.Trạng thái phái sinh.physical_status', { defaults: '' }));

var _teammates = getvar('stat_data.Đồng đội', { defaults: {} });
for (var key in _teammates) {
    if (_teammates[key] && _teammates[key].physical_status) {
        _allPhys.push(_teammates[key].physical_status);
    }
}

var _npcs = getvar('stat_data.NPC', { defaults: {} });
for (var key in _npcs) {
    if (_npcs[key] && _npcs[key].physical_status) {
        _allPhys.push(_npcs[key].physical_status);
    }
}

for (var i = 0; i < _allPhys.length; i++) {
    var _p = _allPhys[i] || '';
    if (_p.includes('kinh nguyệt')) _needPeriodItems = true;
    if (_p.includes('rụng trứng')) _needOvulationItems = true;
    if (_p.includes('mang thai') || _p.includes('có thai')) _isPregnant = true;
    if (_p.includes('thai kỳ cuối')) _isLatePregnancy = true;
    if (_p.includes('sinh nở')) _isLabor = true;
    if (_p.includes('sau sinh') || _p.includes('phục hồi')) _isPostpartum = true;
    if (_p.includes('cho con bú')) _isNursing = true;
}

await activewi(null, 'Cơ chế-Chu kỳ sinh lý nữ', true);
if (_needPeriodItems) await activewi(null, 'Vật phẩm-Băng vệ sinh phụ nữ', true);
if (_needOvulationItems) await activewi(null, 'Vật phẩm-Vật dụng và biện pháp tránh thai', true);

/* Tải cơ chế thai sản chi tiết */
if (_isPregnant || _isLatePregnancy || _isLabor || _isPostpartum || _isNursing) {
    await activewi(null, 'Cơ chế-Thời kỳ mang thai, sinh nở và cho con bú của phụ nữ', true);
}

if (_isPregnant) {
    await activewi(null, 'Vật phẩm-Thuốc và biện pháp phá thai', true);
}

if (_isNursing || _isPostpartum) { // Thời kỳ sau sinh và cho con bú thường chồng chéo hoặc nối tiếp nhau
    await activewi(null, 'Vật phẩm-Dụng cụ y tế đặc biệt cho thai sản và cho con bú', true);
    await activewi(null, 'Vật phẩm-Khẩu phần ăn duy trì sự sống cho trẻ sơ sinh', true);
    await activewi(null, 'Cơ chế-Sinh lý nữ-Khủng hoảng trẻ sơ sinh', true);
    await activewi(null, 'Cơ chế-Quy tắc phe phái-Trẻ sơ sinh và người mẹ', true);
    await activewi(null, 'Cơ chế-Vùng an toàn chính thức-Trung tâm chăm sóc và vắt sữa', true);
    await activewi(null, 'Vật phẩm-Sữa mẹ', true);
    await activewi(null, 'Cơ chế-Vắt sữa mẹ và cách sử dụng', true);
}
